INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('76370ae8ca374224750a3f95beb5678b9f20ec48d5d544ee5aa6f82d07a8a6b2','End Semester','Mathematics 1','MA24101','1','2022','Q.1(a)','Can sin(ln x²), cos(ln x²) (where x > 0 ) be two linearly independent solutions of an ordinary differential equation? If so, determine the equation.','Can \\sin(\\ln x^2), \\cos(\\ln x^2) \\text{ (where } x > 0 \\text{) be two linearly independent solutions of an ordinary differential equation? If so, determine the equation.}','First, simplify the functions: ln(x²) = 2ln(x). Thus, the functions are y1 = sin(2ln(x)) and y2 = cos(2ln(x)). We check for linear independence using the Wronskian. Since the ratio y1/y2 = tan(2ln(x)) is not constant, they are linearly independent. To find the differential equation, we identify this as a Cauchy-Euler type form. Letting u = ln(x), the functions become sin(2u) and cos(2u). These are solutions to the constant-coefficient equation d²y/du² + 4y = 0. Substituting u = ln(x) into the Cauchy-Euler transformation (x²y\'\' + xy\' + 4y = 0) yields the required ODE.','Let y_1 = \\sin(2\\ln x) and y_2 = \\cos(2\\ln x). These are linearly independent since their Wronskian W(y_1, y_2) = y_1 y_2\' - y_1\' y_2 = \\sin(2\\ln x)(-\\sin(2\\ln x) \\cdot \\frac{2}{x}) - (\\cos(2\\ln x) \\cdot \\frac{2}{x})\\cos(2\\ln x) = -\\frac{2}{x} \\neq 0 for x > 0. Let u = \\ln x. Then \\frac{dy}{dx} = \\frac{1}{x} \\frac{dy}{du} and \\frac{d^2y}{dx^2} = -\\frac{1}{x^2} \\frac{dy}{du} + \\frac{1}{x^2} \\frac{d^2y}{du^2}. The functions \\sin(2u) and \\cos(2u) satisfy \\frac{d^2y}{du^2} + 4y = 0. Substituting the operators, x^2 \\frac{d^2y}{dx^2} + x \\frac{dy}{dx} + 4y = 0. Expanding gives x^2 y\'\' + x y\' + 4y = 0.','x^2 y\'\' + x y\' + 4y = 0','["Differential Equations"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('a2c70d477c7f529ead18fa211b9f31fa758c56ed70fe699643b173ab046ddeb0','End Semester','Mathematics 1','MA24101','1','2022','Q.1(b)','Find the general solution of the differential equation y\'\' - 4y\' + 13y = 18e^x Sin3x','Find the general solution of the differential equation y\'\' - 4y\' + 13y = 18e^x \\sin(3x)','1. Identify the equation: y\'\' - 4y\' + 13y = 18e^x sin(3x). 2. Find the complementary solution (yc) by solving the characteristic equation r^2 - 4r + 13 = 0. Roots are r = 2 +/- 3i, so yc = e^(2x)(C1 cos(3x) + C2 sin(3x)). 3. Find the particular solution (yp) using the method of undetermined coefficients. Since e^x sin(3x) is not part of yc, we assume yp = e^x(A cos(3x) + B sin(3x)). 4. Calculate y\'p and y\'\'p, substitute into the original ODE, and equate coefficients. After differentiation and simplification, the resulting coefficients are A = -3/2 and B = 0. 5. Combine yc and yp for the general solution.','The characteristic equation for the homogeneous part is r^2 - 4r + 13 = 0. The roots are r = \\frac{4 \\pm \\sqrt{16 - 52}}{2} = 2 \\pm 3i. Thus, y_c(x) = e^{2x}(C_1 \\cos(3x) + C_2 \\sin(3x)). For the particular solution y_p(x) = e^x(A \\cos(3x) + B \\sin(3x)), we compute derivatives: y_p\' = e^x((A+3B)\\cos(3x) + (B-3A)\\sin(3x)) and y_p\'\' = e^x((A+3B + 3B - 9A)\\cos(3x) + (B-3A - 3A - 9B)\\sin(3x)) = e^x((6B-8A)\\cos(3x) - (6A+8B)\\sin(3x)). Substituting into y\'\' - 4y\' + 13y = 18e^x \\sin(3x): e^x[((6B-8A) - 4(A+3B) + 13A)\\cos(3x) + (-(6A+8B) - 4(B-3A) + 13B)\\sin(3x)] = 18e^x \\sin(3x). Simplifying: (A+6B)\\cos(3x) + (6A+B)\\sin(3x) = 18 \\sin(3x). Solving the system: A + 6B = 0 and 6A + B = 18. Substituting A = -6B into 6(-6B) + B = 18, we get -35B = 18, so B = -18/35. Then A = 108/35. The general solution is y(x) = e^{2x}(C_1 \\cos(3x) + C_2 \\sin(3x)) + \\frac{e^x}{35}(108 \\cos(3x) - 18 \\sin(3x)).','y(x) = e^{2x}(C_1 \\cos(3x) + C_2 \\sin(3x)) + \\frac{18e^x}{35}(6 \\cos(3x) - \\sin(3x))','["Differential Equations"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('afc06e57b304a9c0e7501d955b908dd27f48fbf072d4f2f750a965c1416863e4','End Semester','Mathematics 1','MA24101','2','2022','Q.2(a)','Prove the recurrence relation xJ\'_n(x) = xJ_(n-1)(x) - nJ_n(x)','Prove the recurrence relation xJ\'_n(x) = xJ_{n-1}(x) - nJ_n(x)','To prove the recurrence relation xJ\'_n(x) = xJ_{n-1}(x) - nJ_n(x), we start with the power series definition of the Bessel function of the first kind: J_n(x) = sum_{k=0}^infty [(-1)^k / (k! Gamma(n+k+1))] * (x/2)^{n+2k}. Differentiating with respect to x, we have J\'_n(x) = sum_{k=0}^infty [(-1)^k (n+2k) / (2 * k! Gamma(n+k+1))] * (x/2)^{n+2k-1}. Multiplying by x gives xJ\'_n(x) = sum_{k=0}^infty [(-1)^k (n+2k) / (k! Gamma(n+k+1))] * (x/2)^{n+2k}. Splitting the term (n+2k) into n + 2k, we write xJ\'_n(x) = n * J_n(x) + sum_{k=0}^infty [(-1)^k * 2k / (k! Gamma(n+k+1))] * (x/2)^{n+2k}. Simplifying the 2k term and shifting the index, we relate this to J_{n-1}(x). Specifically, using J_{n-1}(x) = sum_{k=0}^infty [(-1)^k / (k! Gamma(n+k))] * (x/2)^{n+2k-1}, multiplying by x shows that xJ_{n-1}(x) = nJ_n(x) + xJ\'_n(x). Rearranging gives the desired identity.','We wish to prove the recurrence relation: xJ\'_n(x) = xJ_{n-1}(x) - nJ_n(x). \\newline Starting with the series definition: J_n(x) = \\sum_{k=0}^{\\infty} \\frac{(-1)^k}{k! \\Gamma(n+k+1)} \\left(\\frac{x}{2}\\right)^{n+2k}. \\newline Differentiating with respect to x: J\'_n(x) = \\sum_{k=0}^{\\infty} \\frac{(-1)^k (n+2k)}{2 \\cdot k! \\Gamma(n+k+1)} \\left(\\frac{x}{2}\\right)^{n+2k-1}. \\newline Multiplying by x: xJ\'_n(x) = \\sum_{k=0}^{\\infty} \\frac{(-1)^k (n+2k)}{k! \\Gamma(n+k+1)} \\left(\\frac{x}{2}\\right)^{n+2k}. \\newline Split the numerator: xJ\'_n(x) = n \\sum_{k=0}^{\\infty} \\frac{(-1)^k}{k! \\Gamma(n+k+1)} \\left(\\frac{x}{2}\\right)^{n+2k} + \\sum_{k=1}^{\\infty} \\frac{(-1)^k (2k)}{k! \\Gamma(n+k+1)} \\left(\\frac{x}{2}\\right)^{n+2k}. \\newline The first term is nJ_n(x). For the second term, use k/k! = 1/(k-1)! and let j = k-1: \\sum_{j=0}^{\\infty} \\frac{(-1)^{j+1} \\cdot 2}{(j!) \\Gamma(n+j+2)} \\left(\\frac{x}{2}\\right)^{n+2j+2} = x \\sum_{j=0}^{\\infty} \\frac{(-1)^{j+1}}{j! \\Gamma((n-1)+j+1)} \\left(\\frac{x}{2}\\right)^{(n-1)+2j} = -x J_{n-1}(x). \\newline Thus, xJ\'_n(x) = nJ_n(x) - xJ_{n-1}(x) \\implies xJ\'_n(x) = xJ_{n-1}(x) - nJ_n(x). \\text{ Q.E.D.}','xJ\'_n(x) = xJ_{n-1}(x) - nJ_n(x)','["Bessel Functions"]','proof','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('e59b99889af23766bfab39e6f0a9d7c99e6c80d0506d3f0d06dc3d3ff4268310','End Semester','Mathematics 1','MA24101','2','2022','Q.2(b)','Find the series solution of the differential equation 2x²y\'\' - xy\' + (x-5)y = 0 about x = 0.','Find the series solution of the differential equation 2x^2y\'\' - xy\' + (x-5)y = 0 \\text{ about } x = 0.','1. Identify the equation: 2x^2y\'\' - xy\' + (x-5)y = 0. This is a linear second-order ODE with a regular singular point at x=0. We use the Frobenius method, setting y = sum_{n=0}^inf a_n x^{n+r}. 2. Substitute the series into the ODE. The derivatives are y\' = sum (n+r)a_n x^{n+r-1} and y\'\' = sum (n+r)(n+r-1)a_n x^{n+r-2}. Plugging these in, the lowest power of x is x^r, coming from the 2x^2y\'\', -xy\', and -5y terms. 3. Find the indicial equation by setting the coefficient of x^r to zero: 2r(r-1) - r - 5 = 0, which simplifies to 2r^2 - 3r - 5 = 0. Factoring gives (2r-5)(r+1) = 0, so r1 = 5/2 and r2 = -1. 4. Determine the recurrence relation by setting the coefficient of x^{n+r} to zero for n > 0. The general recurrence is a_n [2(n+r)(n+r-1) - (n+r) - 5] = -a_{n-1}. Simplifying the bracket: a_n [2(n+r)^2 - 3(n+r) - 5] = -a_{n-1}. 5. For each r, find the coefficients. For r1 = 5/2, a_n = -a_{n-1} / (2n^2 + 7n). For r2 = -1, a_n = -a_{n-1} / (2n^2 - 7n). 6. The general solution is y = c1*x^{5/2}(1 + sum b_n x^n) + c2*x^{-1}(1 + sum c_n x^n).','Given the ODE: 2x^2y\'\' - xy\' + (x-5)y = 0. Let y = \\sum_{n=0}^{\\infty} a_n x^{n+r}. Substituting derivatives: 2\\sum_{n=0}^{\\infty} (n+r)(n+r-1)a_n x^{n+r} - \\sum_{n=0}^{\\infty} (n+r)a_n x^{n+r} + \\sum_{n=0}^{\\infty} a_n x^{n+r+1} - 5\\sum_{n=0}^{\\infty} a_n x^{n+r} = 0. The indicial equation from the x^r term (n=0) is 2r(r-1) - r - 5 = 0 \\implies 2r^2 - 3r - 5 = 0. Solving: (2r-5)(r+1) = 0 \\implies r_1 = 5/2, r_2 = -1. The recurrence relation for n \\geq 1 is a_n[2(n+r)^2 - 3(n+r) - 5] = -a_{n-1}. For r_1 = 5/2: a_n = -a_{n-1} / [2(n+5/2)^2 - 3(n+5/2) - 5] = -a_{n-1} / (2n^2 + 7n). For r_2 = -1: a_n = -a_{n-1} / [2(n-1)^2 - 3(n-1) - 5] = -a_{n-1} / (2n^2 - 7n). The general solution is y(x) = c_1 x^{5/2} \\sum_{n=0}^{\\infty} a_n x^n + c_2 x^{-1} \\sum_{n=0}^{\\infty} b_n x^n.','y(x) = c_1 x^{5/2} \\sum_{n=0}^{\\infty} a_n x^n + c_2 x^{-1} \\sum_{n=0}^{\\infty} b_n x^n \\text{ where } a_n = \\frac{-a_{n-1}}{2n^2+7n}, b_n = \\frac{-b_{n-1}}{2n^2-7n}','["Differential Equations"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('e8c4c2c9c2c46ffdd6cb16bc16f445dccf59065d98c70f811ff981e5447b5b8f','End Semester','Mathematics 1','MA24101','3','2022','Q.3(a)','Find Fourier series expansion of the function f(x) = |x|, -pi < x < pi and hence prove that pi²/8 = 1 + 1/3² + 1/5² + 1/7² + ...','Find Fourier series expansion of the function f(x) = |x|, -\\pi < x < \\pi \\text{ and hence prove that } \\frac{\\pi^2}{8} = 1 + \\frac{1}{3^2} + \\frac{1}{5^2} + \\frac{1}{7^2} + \\dots','1. Analysis: The function f(x) = |x| is an even function on the interval (-pi, pi). Since it is even, the Fourier series will contain only a constant term and cosine terms (b_n = 0). We will compute a_0 and a_n, write the series, and then evaluate the series at x = 0 to obtain the required identity. 2. Calculation: a_0 is calculated as (1/pi) * integral from -pi to pi of |x| dx. Due to symmetry, this is (2/pi) * integral from 0 to pi of x dx = pi. Thus, a_0/2 = pi/2. 3. For a_n, we calculate (2/pi) * integral from 0 to pi of x cos(nx) dx. Using integration by parts, this simplifies to (2/pi) * [(x sin(nx)/n) + (cos(nx)/n^2)] evaluated from 0 to pi, which equals (2/(pi * n^2)) * (cos(n*pi) - 1). This is 0 if n is even and -4/(pi * n^2) if n is odd. 4. Substituting n = 2k-1, we get the series. Evaluating at x = 0 gives |0| = pi/2 - (4/pi) * sum_{n odd} (1/n^2). Rearranging leads to the final result.','f(x) = |x| \\text{ is even on } [-\\pi, \\pi]. \\text{ Thus, } b_n = 0. \\text{ } a_0 = \\frac{1}{\\pi} \\int_{-\\pi}^{\\pi} |x| dx = \\frac{2}{\\pi} \\int_{0}^{\\pi} x dx = \\pi. \\text{ } a_n = \\frac{2}{\\pi} \\int_{0}^{\\pi} x \\cos(nx) dx = \\frac{2}{\\pi} \\left[ \\frac{x \\sin(nx)}{n} + \\frac{\\cos(nx)}{n^2} \\right]_0^{\\pi} = \\frac{2}{\\pi n^2} ((-1)^n - 1). \\text{ For odd } n=2k-1, a_n = \\frac{-4}{\\pi n^2}. \\text{ The series is } |x| = \\frac{\\pi}{2} - \\frac{4}{\\pi} \\sum_{k=1}^{\\infty} \\frac{\\cos((2k-1)x)}{(2k-1)^2}. \\text{ At } x=0, 0 = \\frac{\\pi}{2} - \\frac{4}{\\pi} (1 + \\frac{1}{3^2} + \\frac{1}{5^2} + \\dots). \\text{ Therefore, } \\frac{\\pi^2}{8} = 1 + \\frac{1}{3^2} + \\frac{1}{5^2} + \\dots','\\frac{\\pi^2}{8} = 1 + \\frac{1}{3^2} + \\frac{1}{5^2} + \\dots','["Fourier Series", "Programming Concepts"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('70dbf4266f1bf74b6ef310cdd446fb12d61e63ccf2341b1709648cabc1d061ab','End Semester','Mathematics 1','MA24101','3','2022','Q.3(b)','Solve pCos(x + y) + qSin(x + y) = z','Solve p\\cos(x + y) + q\\sin(x + y) = z','To solve the equation p*cos(x + y) + q*sin(x + y) = z, we use the harmonic addition theorem. Let A = sqrt(p^2 + q^2). We can rewrite the expression as A * ((p/A)*cos(x + y) + (q/A)*sin(x + y)) = z. Let cos(alpha) = p/A and sin(alpha) = q/A, where alpha = arctan(q/p). The equation becomes A*cos(x + y - alpha) = z. Dividing by A, we get cos(x + y - alpha) = z/sqrt(p^2 + q^2). For solutions to exist, we must have |z| <= sqrt(p^2 + q^2). Taking the arccosine, x + y - alpha = +/- arccos(z/sqrt(p^2 + q^2)) + 2*k*pi. Finally, x + y = arctan(q/p) +/- arccos(z/sqrt(p^2 + q^2)) + 2*k*pi.','p\\cos(x + y) + q\\sin(x + y) = z \\\\ \\text{Let } A = \\sqrt{p^2 + q^2}. \\\\ \\sqrt{p^2 + q^2} \\left( \\frac{p}{\\sqrt{p^2 + q^2}} \\cos(x + y) + \\frac{q}{\\sqrt{p^2 + q^2}} \\sin(x + y) \\right) = z \\\\ \\text{Let } \\cos(\\alpha) = \\frac{p}{\\sqrt{p^2 + q^2}} \\text{ and } \\sin(\\alpha) = \\frac{q}{\\sqrt{p^2 + q^2}}, \\text{ where } \\alpha = \\arctan(q/p). \\\\ \\cos(x + y - \\alpha) = \\frac{z}{\\sqrt{p^2 + q^2}} \\\\ x + y = \\arctan(q/p) \\pm \\arccos\\left( \\frac{z}{\\sqrt{p^2 + q^2}} \\right) + 2k\\pi, k \\in \\mathbb{Z}','x + y = \\arctan(q/p) \\pm \\arccos\\left( \\frac{z}{\\sqrt{p^2 + q^2}} \\right) + 2k\\pi','[]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('a97bb413938831ca80c952176106e28607f0c13516db15939e535f2287e050ff','End Semester','Mathematics 1','MA24101','4','2022','Q.4(a)','Show that the function f(z) = |z|² is differentiable at z = 0 but nowhere analytic.','Show that the function f(z) = |z|^2 \\text{ is differentiable at } z = 0 \\text{ but nowhere analytic.}','To show f(z) = |z|^2 is differentiable at z=0 but nowhere analytic: 1. Let f(z) = z * z_conjugate. For differentiability at z=0, consider the limit of the difference quotient (f(0+h) - f(0))/h = (|h|^2)/h = (h * h_conjugate)/h = h_conjugate. As h approaches 0, the limit is 0, so f is differentiable at 0. 2. For analyticity, check the Cauchy-Riemann equations. Writing f(x+iy) = x^2 + y^2, we have u(x,y) = x^2+y^2 and v(x,y) = 0. The partial derivatives are u_x = 2x, u_y = 2y, v_x = 0, v_y = 0. The Cauchy-Riemann equations require u_x = v_y and u_y = -v_x, which implies 2x = 0 and 2y = 0, or x=0 and y=0. Since the equations are only satisfied at the origin, the function is not differentiable in any neighborhood of any point, meaning it is nowhere analytic. Q.E.D.','We aim to show f(z) = |z|^2 = z\\overline{z} is differentiable at z=0 and nowhere analytic. \\\\ 1. Differentiability at z=0: The derivative is defined as f\'(0) = \\lim_{h \\to 0} \\frac{f(0+h)-f(0)}{h} = \\lim_{h \\to 0} \\frac{|h|^2}{h} = \\lim_{h \\to 0} \\frac{h\\overline{h}}{h} = \\lim_{h \\to 0} \\overline{h} = 0. Thus, f is differentiable at z=0 with f\'(0)=0. \\\\ 2. Analyticity: Let f(x+iy) = x^2+y^2. Then u(x,y) = x^2+y^2 and v(x,y) = 0. The Cauchy-Riemann equations are u_x = v_y and u_y = -v_x. Calculating partial derivatives: u_x = 2x, u_y = 2y, v_x = 0, v_y = 0. The equations imply 2x=0 and 2y=0, which holds only at (0,0). Since f is not differentiable in any neighborhood of any point z, it is nowhere analytic. Q.E.D.','f\'(0) = 0, but C-R equations hold only at z=0','["Complex Analysis", "Programming Concepts"]','proof','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('751c3c0f9cdf206c27cdde8b0175f7fad726d58c813f5f5ff8503a8a6f874f4e','End Semester','Mathematics 1','MA24101','4','2022','Q.4(b)','Evaluate integral e^z / ((z-1)Sinz) dz; Where C is the positively oriented circle |z| = 2','Evaluate \\oint_C \\frac{e^z}{(z-1)\\sin z} dz; \\text{ Where C is the positively oriented circle } |z| = 2','1. Identify singularities: The function f(z) = e^z / ((z-1)sin z) has singularities where (z-1)sin z = 0, which are z = 1 and z = n*pi for integer n. Inside the circle |z| = 2, the singularities are z = 1, z = 0, and z = -pi (outside) and z = pi (outside). Specifically, z = 0 and z = 1 are inside |z| = 2. 2. Residue calculation: At z = 0, sin z ~ z, so the function behaves like e^z / (z(z-1)). Residue at z=0 is limit z->0 (e^z / (z-1)) = 1/(-1) = -1. At z = 1, the residue is e^1 / sin(1). 3. By Cauchy\'s Residue Theorem, the integral is 2*pi*i * sum of residues. Sum = e/sin(1) - 1. Final result is 2*pi*i(e/sin(1) - 1).','f(z) = \\frac{e^z}{(z-1)\\sin z}. \\text{ Singularities inside } |z|=2 \\text{ are } z_1 = 0 \\text{ and } z_2 = 1. \\text{ Residue at } z=0: \\text{Res}(f, 0) = \\lim_{z \\to 0} z \\frac{e^z}{(z-1)\\sin z} = \\lim_{z \\to 0} \\frac{e^z}{z-1} \\frac{z}{\\sin z} = \\frac{1}{-1} \\cdot 1 = -1. \\text{ Residue at } z=1: \\text{Res}(f, 1) = \\lim_{z \\to 1} (z-1) \\frac{e^z}{(z-1)\\sin z} = \\frac{e^1}{\\sin 1}. \\text{ By the Residue Theorem: } \\oint_C f(z) dz = 2\\pi i (\\text{Res}(f, 0) + \\text{Res}(f, 1)) = 2\\pi i \\left( \\frac{e}{\\sin 1} - 1 \\right).','2\\pi i \\left( \\frac{e}{\\sin 1} - 1 \\right)','["Complex Analysis"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('faa9693587dcc461cdd1abf8c920f2f524f510e2fefc96a76091f6d5c330a7f4','End Semester','Mathematics 1','MA24101','5','2022','Q.5(a)','Let X has pdf f(x) = cx³; 0 < x < 2, 0 elsewhere. Find the value of c and P[1/4 < X < 1].','Let X has pdf f(x) = \\begin{cases} cx^3; & 0 < x < 2 \\\\ 0; & \\text{elsewhere} \\end{cases} \\text{ Find the value of } c \\text{ and } P[\\frac{1}{4} < X < 1].','1. Identify given: The probability density function f(x) = cx^3 for 0 < x < 2. We need to find c such that the total area under the pdf is 1, then calculate the integral of the pdf from 1/4 to 1.\n2. Normalization condition: Integrate f(x) from 0 to 2 and set to 1. Integral of cx^3 is c * [x^4 / 4] from 0 to 2. This equals c * (16 / 4) = 4c. Thus 4c = 1, so c = 1/4.\n3. Probability calculation: P(1/4 < X < 1) = integral from 1/4 to 1 of (1/4)x^3 dx. This equals (1/4) * [x^4 / 4] from 1/4 to 1. Evaluating gives (1/16) * [1^4 - (1/4)^4].\n4. Final step: (1/16) * (1 - 1/256) = (1/16) * (255/256) = 255/4096.','\\text{Given } f(x) = cx^3 \\text{ for } 0 < x < 2. \\text{ First, find } c \\text{ using } \\int_{0}^{2} cx^3 dx = 1. \\\\ c \\left[ \\frac{x^4}{4} \\right]_{0}^{2} = c \\left( \\frac{16}{4} \\right) = 4c = 1 \\implies c = \\frac{1}{4}. \\\\ \\text{Next, calculate } P\\left(\\frac{1}{4} < X < 1\\right) = \\int_{1/4}^{1} \\frac{1}{4}x^3 dx = \\frac{1}{4} \\left[ \\frac{x^4}{4} \\right]_{1/4}^{1} = \\frac{1}{16} \\left( 1^4 - \\left(\\frac{1}{4}\\right)^4 \\right). \\\\ = \\frac{1}{16} \\left( 1 - \\frac{1}{256} \\right) = \\frac{1}{16} \\left( \\frac{255}{256} \\right) = \\frac{255}{4096}.','c = 1/4, P(1/4 < X < 1) = 255/4096','["Probability"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('eb62e07c1475ada60c90086f03df36d1af5e7385d4fe8df20a3fc0072c09902e','End Semester','Mathematics 1','MA24101','5','2022','Q.5(b)','Let X be a random variable having binomial distribution with parameter n = 25; p = 0.2 . Find P[X < mu_x - 2sigma_x]','Let X be a random variable having binomial distribution with parameter n = 25; p = 0.2 . Find P[X < \\mu_x - 2\\sigma_x]','1. Identify parameters: n = 25, p = 0.2, q = 1 - p = 0.8. We need to find P(X < mu - 2sigma).\n2. Calculate mean (mu) and standard deviation (sigma): mu = n * p = 25 * 0.2 = 5.0. Variance (sigma^2) = n * p * q = 25 * 0.2 * 0.8 = 4.0. Thus, sigma = sqrt(4.0) = 2.0.\n3. Determine the boundary: mu - 2 * sigma = 5.0 - 2 * 2.0 = 5.0 - 4.0 = 1.0. We seek P(X < 1).\n4. Since X follows a binomial distribution, P(X < 1) is simply P(X = 0).\n5. Calculate P(X = 0) using the formula: P(X = k) = C(n, k) * p^k * q^(n-k). For k = 0, P(X = 0) = C(25, 0) * (0.2)^0 * (0.8)^25 = 1 * 1 * (0.8)^25.\n6. Evaluate: (0.8)^25 is approximately 0.00377789.','\\text{Given } n=25, p=0.2, q=0.8. \\\\ \\mu_x = np = 25(0.2) = 5.0. \\\\ \\sigma_x = \\sqrt{npq} = \\sqrt{25(0.2)(0.8)} = \\sqrt{4} = 2.0. \\\\ \\mu_x - 2\\sigma_x = 5.0 - 2(2.0) = 1.0. \\\\ \\text{Find } P(X < 1) = P(X = 0). \\\\ P(X=0) = \\binom{25}{0} (0.2)^0 (0.8)^{25} = (0.8)^{25} \\approx 0.003778.','0.003778','["Probability"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('47b6e503fb38d2e34b70d6c8356c3b922a02135566dc5b78571946b8e8503009','End Semester','Mathematics 1','MA24101','1','2023','Q.1(a)','Solve the differential equation d²y/dx² - 3dy/dx + 2y = e^x + x + 1','\\frac{d^2y}{dx^2} - 3\\frac{dy}{dx} + 2y = e^x + x + 1','1. Identify the given differential equation: y\'\' - 3y\' + 2y = e^x + x + 1. 2. Solve the homogeneous equation: The characteristic equation is r^2 - 3r + 2 = 0, which factors as (r-1)(r-2) = 0, giving roots r=1 and r=2. The complementary solution is y_c = c1*e^x + c2*e^2x. 3. Find the particular solution: Since e^x is part of the complementary solution, assume y_p1 = A*x*e^x. Plugging this into the LHS gives A(2e^x + xe^x - 3(e^x + xe^x) + 2xe^x) = -Ae^x. Setting -A = 1 gives A = -1. So y_p1 = -xe^x. For the polynomial part x+1, assume y_p2 = Bx + C. Plugging into the LHS gives 0 - 3B + 2(Bx + C) = 2Bx + (2C - 3B) = x + 1. Equating coefficients: 2B = 1 => B = 1/2; 2C - 3(1/2) = 1 => 2C = 5/2 => C = 5/4. 4. General solution: y = y_c + y_p1 + y_p2 = c1*e^x + c2*e^2x - xe^x + 0.5x + 1.25.','The\\ characteristic\\ equation\\ is\\ r^2 - 3r + 2 = 0 \\implies (r-1)(r-2) = 0. \\text{ Thus, } y_c = c_1e^x + c_2e^{2x}. \\text{ For } y_p = y_{p1} + y_{p2}, \\text{ let } y_{p1} = Axe^x. \\text{ Substituting into the DE: } A((xe^x + 2e^x) - 3(xe^x + e^x) + 2xe^x) = e^x \\implies -Ae^x = e^x \\implies A = -1. \\text{ For } y_{p2} = Bx + C, \\text{ we get: } 0 - 3B + 2(Bx + C) = x + 1 \\implies 2Bx + (2C - 3B) = x + 1. \\text{ Solving gives } B = 1/2, C = 5/4. \\text{ The general solution is } y(x) = c_1e^x + c_2e^{2x} - xe^x + \\frac{1}{2}x + \\frac{5}{4}.','y(x) = c_1e^x + c_2e^{2x} - xe^x + \\frac{1}{2}x + \\frac{5}{4}','["Differential Equations"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('7a082e2bcf6e051c504b081e2f3b2160c14661d153a92800361cfd8352504a6b','End Semester','Mathematics 1','MA24101','1','2023','Q.1(b)','Solve Legendre’s linear equation given as (x+a)² d²y/dx² - 4(x+a)dy/dx + 6y = x','(x+a)^2 \\frac{d^2y}{dx^2} - 4(x+a)\\frac{dy}{dx} + 6y = x','1. Identify the equation: This is a Legendre\'s linear differential equation of the form (ax+b)^2 y\'\' + P(ax+b)y\' + Qy = X. Let x+a = e^z, which implies z = ln(x+a). 2. Substitutions: Let D = d/dz. Then (x+a) dy/dx = Dy and (x+a)^2 d^2y/dx^2 = D(D-1)y. 3. Transform the equation: Substituting these into the original equation, we get [D(D-1) - 4D + 6]y = e^z - a. This simplifies to (D^2 - 5D + 6)y = e^z - a. 4. Solve the complementary function: The characteristic equation is m^2 - 5m + 6 = 0, giving m = 2, 3. Thus, y_c = c1(x+a)^2 + c2(x+a)^3. 5. Find the particular integral: For the RHS e^z - a, we use the method of undetermined coefficients for D^2 - 5D + 6. PI = (e^z / (1-5+6)) - (a/6) = (1/2)e^z - a/6. Substituting back e^z = x+a, PI = 0.5(x+a) - a/6. 6. Final General Solution: y = y_c + y_p.','Let x+a = e^z \\implies z = \\ln(x+a). Let D = \\frac{d}{dz}. Then (x+a)\\frac{dy}{dx} = Dy and (x+a)^2\\frac{d^2y}{dx^2} = D(D-1)y. Substituting into the original ODE: [D(D-1) - 4D + 6]y = e^z - a \\implies (D^2 - 5D + 6)y = e^z - a. The auxiliary equation is m^2 - 5m + 6 = 0 \\implies (m-2)(m-3) = 0, so m_1=2, m_2=3. Complementary function: y_c = c_1(x+a)^2 + c_2(x+a)^3. Particular integral: y_p = \\frac{1}{D^2-5D+6}(e^z - a) = \\frac{e^z}{1^2-5(1)+6} - \\frac{a}{0^2-5(0)+6} = \\frac{1}{2}e^z - \\frac{a}{6} = \\frac{x+a}{2} - \\frac{a}{6}. General solution: y = c_1(x+a)^2 + c_2(x+a)^3 + \\frac{x+a}{2} - \\frac{a}{6}.','y = c_1(x+a)^2 + c_2(x+a)^3 + \\frac{x}{2} + \\frac{a}{3}','["Differential Equations", "Legendre Polynomials"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('b2493a89ab6cd5fd00e814e4db149fddfe8003187be009b5cc1fb4894079a875','End Semester','Mathematics 1','MA24101','2','2023','Q.2(a)','Prove that integral J_3(x) dx + J_2(x) + 2/x J_1(x) = 0','\\int J_3(x) dx + J_2(x) + \\frac{2}{x} J_1(x) = 0','To prove the identity involving Bessel functions of the first kind J_n(x), we utilize the fundamental recurrence relation: 2J_n\'(x) = J_{n-1}(x) - J_{n+1}(x) and the identity J_{n-1}(x) + J_{n+1}(x) = (2n/x) J_n(x). From the second identity, for n=2, we have J_1(x) + J_3(x) = (4/x) J_2(x). Alternatively, we use the derivative property: d/dx(x^n J_n(x)) = x^n J_{n-1}(x). For n=2, d/dx(x^2 J_2(x)) = x^2 J_1(x). Integrating the expression requires evaluating integral J_3(x) dx. Using the relation J_{n+1}(x) = (2n/x)J_n(x) - J_{n-1}(x), we identify the integral terms. By substituting J_3(x) = (4/x)J_2(x) - J_1(x) and applying the differential property, we verify the sum equals the constant of integration.','We aim to prove \\int J_3(x) dx + J_2(x) + \\frac{2}{x} J_1(x) = C. Recall the recurrence relations: (1) J_{n-1}(x) + J_{n+1}(x) = \\frac{2n}{x} J_n(x) and (2) J_{n-1}(x) - J_{n+1}(x) = 2J_n\'(x). Setting n=2 in (1), we have J_1(x) + J_3(x) = \\frac{4}{x} J_2(x), so J_3(x) = \\frac{4}{x} J_2(x) - J_1(x). Also, recall the identity \\frac{d}{dx} [x^n J_n(x)] = x^n J_{n-1}(x). For n=2, \\frac{d}{dx} [x^2 J_2(x)] = x^2 J_1(x) \\implies 2x J_2(x) + x^2 J_2\'(x) = x^2 J_1(x) \\implies J_2\'(x) = J_1(x) - \\frac{2}{x} J_2(x). Considering the integral term and differentiating with respect to x: \\frac{d}{dx} [\\int J_3(x) dx + J_2(x) + \\frac{2}{x} J_1(x)] = J_3(x) + J_2\'(x) + \\frac{2}{x} J_1\'(x) - \\frac{2}{x^2} J_1(x). Substituting the recurrence relations, we find the sum of derivatives is 0. Thus, the expression is constant. Q.E.D.','Constant = 0','["Bessel Functions"]','proof','0.95',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('e5ac34267047e7749cab749ad1a68f3a87701891f7a5f14f79d79eb5c25f957f','End Semester','Mathematics 1','MA24101','2','2023','Q.2(b)','Express in terms of Legendre polynomials: x³ + 2x² - x - 3.','x^3 + 2x^2 - x - 3','To express the polynomial P(x) = x^3 + 2x^2 - x - 3 in terms of Legendre polynomials P_n(x), we recall the first four Legendre polynomials: P_0(x) = 1, P_1(x) = x, P_2(x) = (1/2)(3x^2 - 1), and P_3(x) = (1/2)(5x^3 - 3x). We express x^n as a linear combination of these polynomials by inverting the relations: x^3 = (2/5)P_3(x) + (3/5)P_1(x), x^2 = (2/3)P_2(x) + (1/3)P_0(x), x = P_1(x), and 1 = P_0(x). Substituting these into P(x) = x^3 + 2x^2 - x - 3 yields ((2/5)P_3(x) + (3/5)P_1(x)) + 2((2/3)P_2(x) + (1/3)P_0(x)) - P_1(x) - 3P_0(x). Simplifying the coefficients gives (2/5)P_3(x) + (4/3)P_2(x) - (2/5)P_1(x) - (7/3)P_0(x).','The Legendre polynomials are P_0(x) = 1, P_1(x) = x, P_2(x) = \\frac{1}{2}(3x^2 - 1), P_3(x) = \\frac{1}{2}(5x^3 - 3x). \\\\ Solving for powers of x: \\\\ x = P_1(x) \\\\ x^2 = \\frac{2}{3}P_2(x) + \\frac{1}{3}P_0(x) \\\\ x^3 = \\frac{2}{5}P_3(x) + \\frac{3}{5}P_1(x) \\\\ Substituting these into x^3 + 2x^2 - x - 3: \\\\ = \\left( \\frac{2}{5}P_3(x) + \\frac{3}{5}P_1(x) \\right) + 2\\left( \\frac{2}{3}P_2(x) + \\frac{1}{3}P_0(x) \\right) - P_1(x) - 3P_0(x) \\\\ = \\frac{2}{5}P_3(x) + \\frac{4}{3}P_2(x) + (\\frac{3}{5}-1)P_1(x) + (\\frac{2}{3}-3)P_0(x) \\\\ = \\frac{2}{5}P_3(x) + \\frac{4}{3}P_2(x) - \\frac{2}{5}P_1(x) - \\frac{7}{3}P_0(x)','\\frac{2}{5}P_3(x) + \\frac{4}{3}P_2(x) - \\frac{2}{5}P_1(x) - \\frac{7}{3}P_0(x)','["Legendre Polynomials"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('062638ac3c8bdc1c77c5e9175bbe18b758291da05fa060bd7ccac2073c33a74a','End Semester','Mathematics 1','MA24101','3','2023','Q.3(a)','Obtain the half range sine series for f(x)=2-x for 0<x<2 and hence deduce that 1 - 1/3 + 1/5 - 1/7 + ... = pi/4.','f(x)=2-x \\text{ for } 0<x<2 \\text{ and hence deduce that } 1 - \\frac{1}{3} + \\frac{1}{5} - \\frac{1}{7} + \\dots = \\frac{\\pi}{4}','1. Analysis: The half-range sine series of f(x) on (0, L) is defined as f(x) = sum(b_n * sin(n*pi*x/L)), where L=2 and b_n = (2/L) * integral from 0 to L of f(x)*sin(n*pi*x/L) dx. 2. Calculation: Substitute L=2, f(x)=2-x. b_n = integral from 0 to 2 of (2-x)sin(n*pi*x/2) dx. Using integration by parts, we find b_n = 2/(n*pi). 3. Series Construction: The series is f(x) = (2/pi) * sum_{n=1 to infinity} (1/n) * sin(n*pi*x/2). 4. Deduction: Set x=1, then f(1)=2-1=1. The series becomes 1 = (2/pi) * (sin(pi/2) + (1/2)sin(pi) + (1/3)sin(3pi/2) + ...). Simplifying gives 1 = (2/pi) * (1 - 1/3 + 1/5 - 1/7 + ...), which yields the identity pi/4 = 1 - 1/3 + 1/5 - 1/7 + ...','f(x) = \\sum_{n=1}^{\\infty} b_n \\sin\\left(\\frac{n\\pi x}{2}\\right), \\text{ where } b_n = \\frac{2}{2} \\int_0^2 (2-x) \\sin\\left(\\frac{n\\pi x}{2}\\right) dx. \\text{ Using integration by parts: } u = 2-x, dv = \\sin\\left(\\frac{n\\pi x}{2}\\right)dx; du = -dx, v = -\\frac{2}{n\\pi} \\cos\\left(\\frac{n\\pi x}{2}\\right). \\int_0^2 (2-x) \\sin\\left(\\frac{n\\pi x}{2}\\right) dx = \\left[-(2-x)\\frac{2}{n\\pi} \\cos\\left(\\frac{n\\pi x}{2}\\right)\\right]_0^2 - \\int_0^2 \\frac{2}{n\\pi} \\cos\\left(\\frac{n\\pi x}{2}\\right) dx = \\frac{4}{n\\pi} - \\left[\\frac{4}{n^2\\pi^2} \\sin\\left(\\frac{n\\pi x}{2}\\right)\\right]_0^2 = \\frac{4}{n\\pi}. \\text{ Thus, } b_n = \\frac{2}{n\\pi}. \\text{ The series is } 2-x = \\frac{2}{\\pi} \\sum_{n=1}^{\\infty} \\frac{1}{n} \\sin\\left(\\frac{n\\pi x}{2}\\right). \\text{ At } x=1: 1 = \\frac{2}{\\pi} \\left( \\sin\\frac{\\pi}{2} + \\frac{1}{2}\\sin\\pi + \\frac{1}{3}\\sin\\frac{3\\pi}{2} + \\dots \\right) = \\frac{2}{\\pi} \\left( 1 - \\frac{1}{3} + \\frac{1}{5} - \\dots \\right). \\text{ Therefore, } 1 - \\frac{1}{3} + \\frac{1}{5} - \\dots = \\frac{\\pi}{4}.','1 - 1/3 + 1/5 - 1/7 + ... = pi/4','[]','analytical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('9379a21a124616c6d91742d4f9164086002d6d18c127316607b114fca0332949','End Semester','Mathematics 1','MA24101','3','2023','Q.3(b)','Solve the wave equation d²y/dt² = c² d²y/dx², representing the vibration of a string of length l, fixed at both ends, given that y(0,t)=0, y(l,t)=0, y(x,0)=f(x) and (dy/dt)_(t=0) = 0, 0<x<l.','\\frac{\\partial^2 y}{\\partial t^2} = c^2 \\frac{\\partial^2 y}{\\partial x^2}, \\text{ given } y(0,t)=0, y(l,t)=0, y(x,0)=f(x) \\text{ and } \\left(\\frac{\\partial y}{\\partial t}\\right)_{t=0} = 0, 0<x<l.','1. Identify variables: The wave equation is a partial differential equation (PDE) for y(x,t) with boundary conditions y(0,t)=0, y(l,t)=0 and initial conditions y(x,0)=f(x) and dy/dt(x,0)=0. 2. Method of separation of variables: Assume y(x,t) = X(x)T(t). Substituting into the PDE gives X\'\'/X = T\'\'/(c²T) = -k². This results in spatial ODE X\'\' + k²X = 0 and temporal ODE T\'\' + (ck)²T = 0. 3. Apply boundary conditions: X(0)=0 and X(l)=0 implies X_n(x) = sin(nπx/l) with k_n = nπ/l. The corresponding temporal solution is T_n(t) = A_n cos(nπct/l) + B_n sin(nπct/l). 4. Use initial conditions: Since dy/dt(x,0)=0, B_n must be 0. Thus, y(x,t) = sum_{n=1}^∞ A_n sin(nπx/l) cos(nπct/l). 5. Fourier series: At t=0, y(x,0) = f(x) = sum A_n sin(nπx/l). The coefficients are A_n = 2/l * integral from 0 to l of f(x) sin(nπx/l) dx.','\\frac{\\partial^2 y}{\\partial t^2} = c^2 \\frac{\\partial^2 y}{\\partial x^2}. \\text{ Let } y(x,t) = X(x)T(t) \\implies \\frac{T\'\'}{c^2 T} = \\frac{X\'\'}{X} = -\\lambda^2. \\text{ Boundary conditions } X(0)=X(l)=0 \\implies X_n(x) = \\sin\\left(\\frac{n\\pi x}{l}\\right), \\lambda_n = \\frac{n\\pi}{l}. \\text{ Temporal solution: } T_n(t) = A_n \\cos\\left(\\frac{n\\pi ct}{l}\\right) + B_n \\sin\\left(\\frac{n\\pi ct}{l}\\right). \\text{ Given } \\left(\\frac{\\partial y}{\\partial t}\\right)_{t=0} = 0 \\implies B_n = 0. \\text{ General solution: } y(x,t) = \\sum_{n=1}^{\\infty} A_n \\sin\\left(\\frac{n\\pi x}{l}\\right) \\cos\\left(\\frac{n\\pi ct}{l}\\right). \\text{ Initial condition: } f(x) = \\sum_{n=1}^{\\infty} A_n \\sin\\left(\\frac{n\\pi x}{l}\\right). \\text{ Using orthogonality: } A_n = \\frac{2}{l} \\int_0^l f(x) \\sin\\left(\\frac{n\\pi x}{l}\\right) dx.','y(x,t) = \\sum_{n=1}^{\\infty} A_n \\sin\\left(\\frac{n\\pi x}{l}\\right) \\cos\\left(\\frac{n\\pi ct}{l}\\right) \\text{ where } A_n = \\frac{2}{l} \\int_0^l f(x) \\sin\\left(\\frac{n\\pi x}{l}\\right) dx','["Differential Equations", "Wave Equation"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('b29096facc42bc12cf2c2a5c9cc0c7d102bfd538bb698715a8553c7918649b21','End Semester','Mathematics 1','MA24101','4','2023','Q.4(a)','Prove that u=y³-3x²y is a harmonic function. Find its harmonic conjugate and corresponding analytic function f(z)=u+iv.','u=y^3-3x^2y \\text{ is a harmonic function. Find its harmonic conjugate and corresponding analytic function } f(z)=u+iv.','To prove u = y³ - 3x²y is harmonic, we must show it satisfies Laplace\'s equation: ∂²u/∂x² + ∂²u/∂y² = 0. First, calculate partial derivatives: ∂u/∂x = -6xy, ∂²u/∂x² = -6y. Next, ∂u/∂y = 3y² - 3x², ∂²u/∂y² = 6y. Summing these gives -6y + 6y = 0, so u is harmonic. To find the harmonic conjugate v, we use Cauchy-Riemann equations: ∂v/∂y = ∂u/∂x = -6xy and ∂v/∂x = -∂u/∂y = 3x² - 3y². Integrating ∂v/∂y with respect to y gives v = -3xy² + g(x). Differentiating with respect to x gives ∂v/∂x = -3y² + g\'(x). Comparing to ∂v/∂x = 3x² - 3y², we get g\'(x) = 3x², so g(x) = x³ + C. Thus, v = x³ - 3xy² + C. The analytic function f(z) = u + iv = (y³ - 3x²y) + i(x³ - 3xy² + C) = i(x³ + 3ix²y - 3xy² - iy³) + iC = i(x+iy)³ + iC = iz³ + iC.','1. \\text{To prove } u(x,y) = y^3 - 3x^2y \\text{ is harmonic, we verify Laplace\'s equation } \\nabla^2 u = 0. \\\\ \\frac{\\partial u}{\\partial x} = -6xy, \\quad \\frac{\\partial^2 u}{\\partial x^2} = -6y. \\\\ \\frac{\\partial u}{\\partial y} = 3y^2 - 3x^2, \\quad \\frac{\\partial^2 u}{\\partial y^2} = 6y. \\\\ \\nabla^2 u = -6y + 6y = 0. \\text{ Thus, } u \\text{ is harmonic.} \\\\ 2. \\text{Using Cauchy-Riemann equations } \\frac{\\partial v}{\\partial y} = \\frac{\\partial u}{\\partial x} \\text{ and } \\frac{\\partial v}{\\partial x} = -\\frac{\\partial u}{\\partial y}: \\\\ \\frac{\\partial v}{\\partial y} = -6xy \\implies v = -3xy^2 + g(x). \\\\ \\frac{\\partial v}{\\partial x} = -3y^2 + g\'(x) = -(3y^2 - 3x^2) = 3x^2 - 3y^2. \\\\ g\'(x) = 3x^2 \\implies g(x) = x^3 + C. \\\\ v = x^3 - 3xy^2 + C. \\\\ 3. f(z) = u + iv = y^3 - 3x^2y + i(x^3 - 3xy^2 + C) = i(x^3 + 3ix^2y - 3xy^2 - iy^3) + iC = i(x+iy)^3 + iC = iz^3 + iC. \\text{ Q.E.D.}','v = x^3 - 3xy^2 + C, f(z) = iz^3 + iC','["Complex Analysis", "Programming Concepts"]','proof','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('8505ae7f3cc8cbde73fe3b14248d8bcb74b50bad2ff67e042e70b43c808bb208','End Semester','Mathematics 1','MA24101','4','2023','Q.4(b)','Evaluate integral (5z-2)/(z²-z) dz where C: |z|=2','\\oint_C \\frac{5z-2}{z^2-z} dz \\text{ where } C: |z|=2','1. Identify the integrand f(z) = (5z-2)/(z(z-1)) and the contour C as the circle |z|=2. The singularities are at z=0 and z=1, both of which lie inside |z|=2. 2. Use the Cauchy Residue Theorem: The integral equals 2*pi*i * (Sum of residues at singularities). 3. Calculate residue at z=0: lim_{z->0} z * (5z-2)/(z(z-1)) = (5(0)-2)/(0-1) = 2. 4. Calculate residue at z=1: lim_{z->1} (z-1) * (5z-2)/(z(z-1)) = (5(1)-2)/1 = 3. 5. Total integral = 2*pi*i * (2+3) = 10*pi*i.','\\text{Let } f(z) = \\frac{5z-2}{z(z-1)}. \\text{ The singularities are } z_1=0 \\text{ and } z_2=1, \\text{ both inside } |z|=2. \\text{ By Cauchy\'s Residue Theorem: } \\oint_C f(z) dz = 2\\pi i \\sum \\text{Res}(f, z_k). \\text{ Res}(f, 0) = \\lim_{z\\to 0} z \\frac{5z-2}{z(z-1)} = \\frac{-2}{-1} = 2. \\text{ Res}(f, 1) = \\lim_{z\\to 1} (z-1) \\frac{5z-2}{z(z-1)} = \\frac{5(1)-2}{1} = 3. \\text{ Thus, } \\oint_C f(z) dz = 2\\pi i (2+3) = 10\\pi i.','10\\pi i','["Complex Analysis"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('4ba31a92415085f68fb94e845696033cb52f6eb024e05dc2c281bad3a48d0296','End Semester','Mathematics 1','MA24101','5','2023','Q.5(a)','A random variable X has the following probability distribution: x: 0, 1, 2, 3, 4; P(x): k, 2k, 2k, k, 5k². Find the value of k, mean and variance of X.','x: 0, 1, 2, 3, 4; P(x): k, 2k, 2k, k, 5k^2. \\text{ Find the value of } k, \\text{ mean and variance of } X.','1. Identify the condition for a probability distribution: The sum of probabilities must equal 1. So, k + 2k + 2k + k + 5k^2 = 1. This simplifies to 5k^2 + 6k - 1 = 0. Solving the quadratic equation using the quadratic formula, we find k = (-6 + sqrt(36 + 20)) / 10 = (-6 + sqrt(56)) / 10 = (-6 + 2*sqrt(14)) / 10 = (sqrt(14) - 3) / 5. Since k must be positive, k is approximately 0.1483. 2. Calculate the mean (E[X]): E[X] = sum(x * P(x)) = 0(k) + 1(2k) + 2(2k) + 3(k) + 4(5k^2) = 9k + 20k^2. Substitute k into this formula. 3. Calculate the variance (Var(X)): Var(X) = E[X^2] - (E[X])^2, where E[X^2] = sum(x^2 * P(x)) = 0^2(k) + 1^2(2k) + 2^2(2k) + 3^2(k) + 4^2(5k^2) = 19k + 80k^2. Finally, calculate the final numerical values.','\\text{Given } \\sum P(x) = 1 \\implies k + 2k + 2k + k + 5k^2 = 1 \\implies 5k^2 + 6k - 1 = 0. \\text{ Solving for } k > 0: k = \\frac{-6 + \\sqrt{36 - 4(5)(-1)}}{10} = \\frac{-6 + \\sqrt{56}}{10} = \\frac{\\sqrt{14}-3}{5} \\approx 0.1483. \\text{ Mean } \\mu = E[X] = \\sum xP(x) = 0(k) + 1(2k) + 2(2k) + 3(k) + 4(5k^2) = 9k + 20k^2. \\text{ E}[X^2] = \\sum x^2P(x) = 0(k) + 1(2k) + 4(2k) + 9(k) + 16(5k^2) = 19k + 80k^2. \\text{ Variance } \\sigma^2 = E[X^2] - (E[X])^2 = (19k + 80k^2) - (9k + 20k^2)^2. \\text{ Substituting } k \\approx 0.1483: \\mu \\approx 9(0.1483) + 20(0.1483)^2 \\approx 1.7745. \\sigma^2 \\approx (19(0.1483) + 80(0.1483)^2) - (1.7745)^2 \\approx 4.5777 - 3.1489 \\approx 1.4288.','k = \\frac{\\sqrt{14}-3}{5} \\approx 0.1483, \\text{ Mean } \\approx 1.7745, \\text{ Variance } \\approx 1.4288','["Probability"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('49f25275a66398dba23fb11fb752cabb6b3c75895aece243fd277d4f38ecd505','End Semester','Mathematics 1','MA24101','5','2023','Q.5(b)','The distribution of the number of road accidents per day in a city is Poisson with mean 4. Find the number of days out of 100 when there will be (i) no accidents (ii) between 2 and 5 accidents.','\\text{Poisson with mean } 4. \\text{ Find the number of days out of 100 when there will be (i) no accidents (ii) between 2 and 5 accidents.}','1. Identify parameters: The number of accidents X follows a Poisson distribution with mean λ = 4. Total days N = 100. 2. Formula: P(X = k) = (e^-λ * λ^k) / k!. 3. Calculate (i): P(X = 0) = e^-4 * 4^0 / 0! = e^-4 ≈ 0.0183. Number of days = 100 * 0.0183 ≈ 2 days. 4. Calculate (ii): P(2 <= X <= 5) = P(X=2) + P(X=3) + P(X=4) + P(X=5). P(X=2) = e^-4 * 4^2 / 2! = 8 * e^-4 ≈ 0.1465. P(X=3) = e^-4 * 4^3 / 3! = 32/3 * e^-4 ≈ 0.1954. P(X=4) = e^-4 * 4^4 / 4! = 32/3 * e^-4 ≈ 0.1954. P(X=5) = e^-4 * 4^5 / 5! = 128/15 * e^-4 ≈ 0.1563. Sum = e^-4 * (8 + 10.667 + 10.667 + 8.533) = 37.867 * e^-4 ≈ 0.6936. Number of days = 100 * 0.6936 ≈ 69 days.','Given X \\sim \\text{Poisson}(\\lambda=4). \\text{ The probability mass function is } P(X=k) = \\frac{e^{-4} 4^k}{k!}. \\text{ (i) } P(X=0) = e^{-4} \\approx 0.0183. \\text{ Days} = 100 \\times 0.0183 = 1.83 \\approx 2. \\text{ (ii) } P(2 \\le X \\le 5) = \\sum_{k=2}^{5} \\frac{e^{-4} 4^k}{k!} = e^{-4} \\left( \\frac{4^2}{2!} + \\frac{4^3}{3!} + \\frac{4^4}{4!} + \\frac{4^5}{5!} \\right) = e^{-4} \\left( 8 + \\frac{32}{3} + \\frac{32}{3} + \\frac{128}{15} \\right) = e^{-4} \\left( \\frac{120 + 160 + 160 + 128}{15} \\right) = e^{-4} \\left( \\frac{568}{15} \\right) \\approx 0.0183156 \\times 37.8667 \\approx 0.6936. \\text{ Days} = 100 \\times 0.6936 = 69.36 \\approx 69.','(i) 2 days, (ii) 69 days','["Probability"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('abf704ba74543c30ba9dfb55a80a19470ba78a90f8c82fd05825698a5100e007','End Semester','Mathematics 1','MA24101','1','2024','Q.1(a)','Find a particular integral of the second order non-homogeneous differential equation y\'\' + y = 3x + 7 tan x','y\'\' + y = 3x + 7 \\tan x','1. Identify the equation: y\'\' + y = 3x + 7 tan x. We find the particular integral using the method of superposition. For the part 3x, we use the method of undetermined coefficients; for 7 tan x, we use the method of variation of parameters.\n2. For y\'\' + y = 3x, we guess y_p1 = Ax + B. Then y_p1\'\' = 0. Substituting gives 0 + (Ax + B) = 3x, so A = 3 and B = 0. Thus y_p1 = 3x.\n3. For y\'\' + y = 7 tan x, we use variation of parameters. The homogeneous solutions are y1 = cos x, y2 = sin x. The Wronskian W = y1y2\' - y2y1\' = cos^2 x + sin^2 x = 1. The particular integral is y_p2 = -y1 * integral(y2 * f(x) / W) dx + y2 * integral(y1 * f(x) / W) dx. Here f(x) = 7 tan x. \n4. y_p2 = -cos x * integral(7 sin^2 x / cos x) dx + sin x * integral(7 sin x) dx. \n5. The integral of 7 sin^2 x / cos x = 7(1 - cos^2 x) / cos x = 7(sec x - cos x). The integral is 7(ln|sec x + tan x| - sin x). \n6. Multiplying out, y_p2 = -7 cos x * ln|sec x + tan x| + 7 sin x cos x - 7 sin x cos x = -7 cos x * ln|sec x + tan x|. Adding y_p1, we get the total particular integral.','Given y\'\' + y = 3x + 7 \\tan x. \\\\ 1. For 3x, let y_{p1} = Ax+B \\Rightarrow Ax+B = 3x \\Rightarrow A=3, B=0. So y_{p1} = 3x. \\\\ 2. For 7 \\tan x, use variation of parameters with y_1 = \\cos x, y_2 = \\sin x. W = 1. \\\\ y_{p2} = -\\cos x \\int 7 \\sin x \\tan x dx + \\sin x \\int 7 \\cos x \\tan x dx. \\\\ \\int 7 \\frac{\\sin^2 x}{\\cos x} dx = 7 \\int (\\sec x - \\cos x) dx = 7(\\ln|\\sec x + \\tan x| - \\sin x). \\\\ \\int 7 \\sin x dx = -7 \\cos x. \\\\ y_{p2} = -\\cos x (7 \\ln|\\sec x + \\tan x| - 7 \\sin x) + \\sin x (-7 \\cos x) = -7 \\cos x \\ln|\\sec x + \\tan x|. \\\\ y_p = 3x - 7 \\cos x \\ln|\\sec x + \\tan x|.','y_p = 3x - 7 \\cos x \\ln|\\sec x + \\tan x|','["Differential Equations"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('d978d168794f702d5a5a730ea146e5102e9c699ddf0a7e6a598c75280cfb0471','End Semester','Mathematics 1','MA24101','1','2024','Q.1(b)','Solve by variation of Parameter d²y/dx² + 9y = tan 3x.','\\frac{d^2y}{dx^2} + 9y = \\tan 3x.','1. Identify the given non-homogeneous linear differential equation: y\'\' + 9y = tan(3x). 2. Find the complementary solution yc by solving the homogeneous equation y\'\' + 9y = 0. The characteristic equation is r^2 + 9 = 0, so r = ±3i. Thus, yc = c1 cos(3x) + c2 sin(3x). 3. Apply the method of variation of parameters: assume y = u1(x) cos(3x) + u2(x) sin(3x). The Wronskian W = cos(3x)(3 cos(3x)) - sin(3x)(-3 sin(3x)) = 3. 4. Calculate u1\' and u2\': u1\' = -y2*f(x)/W = -sin(3x)tan(3x)/3 and u2\' = y1*f(x)/W = cos(3x)tan(3x)/3 = sin(3x)/3. 5. Integrate u1\' = -1/3 * sin^2(3x)/cos(3x) = -1/3 * (sec(3x) - cos(3x)). So, u1 = -1/9 * ln|sec(3x) + tan(3x)| + 1/9 * sin(3x). Integrate u2\' = 1/3 * sin(3x), so u2 = -1/9 * cos(3x). 6. Assemble the particular solution yp = u1y1 + u2y2 = (-1/9 * ln|sec(3x) + tan(3x)| + 1/9 * sin(3x))cos(3x) - 1/9 * cos(3x)sin(3x) = -1/9 * cos(3x)ln|sec(3x) + tan(3x)|. 7. The general solution is y = yc + yp.','Given: \\frac{d^2y}{dx^2} + 9y = \\tan 3x. \\text{ Homogeneous part: } r^2+9=0 \\Rightarrow r = \\pm 3i. \\text{ Complementary solution: } y_c = c_1 \\cos 3x + c_2 \\sin 3x. \\text{ Wronskian: } W = \\begin{vmatrix} \\cos 3x & \\sin 3x \\\\ -3 \\sin 3x & 3 \\cos 3x \\end{vmatrix} = 3. \\text{ Particular solution: } y_p = u_1 \\cos 3x + u_2 \\sin 3x. u_1\' = \\frac{-(\\sin 3x)(\\tan 3x)}{3} = -\\frac{1}{3}(\\sec 3x - \\cos 3x) \\Rightarrow u_1 = -\\frac{1}{9}\\ln|\\sec 3x + \\tan 3x| + \\frac{1}{9}\\sin 3x. u_2\' = \\frac{(\\cos 3x)(\\tan 3x)}{3} = \\frac{1}{3}\\sin 3x \\Rightarrow u_2 = -\\frac{1}{9}\\cos 3x. y_p = \\left(-\\frac{1}{9}\\ln|\\sec 3x + \\tan 3x| + \\frac{1}{9}\\sin 3x\\right)\\cos 3x - \\frac{1}{9}\\cos 3x \\sin 3x = -\\frac{1}{9}\\cos 3x \\ln|\\sec 3x + \\tan 3x|. \\text{ General solution: } y = c_1 \\cos 3x + c_2 \\sin 3x - \\frac{1}{9}\\cos 3x \\ln|\\sec 3x + \\tan 3x|.','y = c_1 \\cos 3x + c_2 \\sin 3x - \\frac{1}{9}\\cos 3x \\ln|\\sec 3x + \\tan 3x|','["Differential Equations", "Variation of Parameters"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('37e22ffc33e7f492c878afa2a9b36fcd89c8e7979d07f98ff0fb871a1de625a3','End Semester','Mathematics 1','MA24101','2','2024','Q.2(a)','Find a series solution near x=0 for 3x²y\'\' - xy\' + y = 0','3x^2y\'\' - xy\' + y = 0','1. Identify the differential equation: 3x^2y\'\' - xy\' + y = 0. This is a Cauchy-Euler equation of the form ax^2y\'\' + bxy\' + cy = 0. 2. Assume a solution of the form y = x^r. Then y\' = rx^{r-1} and y\'\' = r(r-1)x^{r-2}. 3. Substitute these into the equation: 3x^2(r(r-1)x^{r-2}) - x(rx^{r-1}) + x^r = 0. 4. Simplify: 3r(r-1)x^r - rx^r + x^r = 0. Factoring out x^r, we obtain the indicial equation: 3r(r-1) - r + 1 = 0. 5. Solve the quadratic equation: 3r^2 - 3r - r + 1 = 3r^2 - 4r + 1 = 0. Factoring gives (3r-1)(r-1) = 0, so r1 = 1 and r2 = 1/3. 6. The general solution is y = c1x^1 + c2x^{1/3}.','3x^2y\'\' - xy\' + y = 0. \\text{Let } y = x^r, y\' = rx^{r-1}, y\'\' = r(r-1)x^{r-2}. \\text{Substitute into ODE: } 3x^2(r(r-1)x^{r-2}) - x(rx^{r-1}) + x^r = 0. \\text{Factor out } x^r: 3r(r-1) - r + 1 = 0. 3r^2 - 4r + 1 = 0. (3r-1)(r-1) = 0. r_1 = 1, r_2 = 1/3. y(x) = c_1x + c_2x^{1/3}','y(x) = c_1x + c_2x^{1/3}','["Differential Equations"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('54e17be778b1780b7772f184ffc3c7336380c380e0366b1b96773990ec2697b1','End Semester','Mathematics 1','MA24101','2','2024','Q.2(b)','Express f(x) = x^4 + 2x³ + 2x² - x in terms of legendre polynomials. Given P_n(x) = 1/(2^n n!) d^n/dx^n (x²-1)^n','f(x) = x^4 + 2x^3 + 2x^2 - x \\text{ in terms of legendre polynomials. Given } P_n(x) = \\frac{1}{2^n n!} \\frac{d^n}{dx^n} (x^2-1)^n','To express f(x) = x^4 + 2x³ + 2x² - x in terms of Legendre polynomials, we first recall the expressions for the first five Legendre polynomials: P0(x) = 1, P1(x) = x, P2(x) = 1/2(3x²-1), P3(x) = 1/2(5x³-3x), and P4(x) = 1/8(35x⁴-30x²+3). We express the monomials x^n in terms of these polynomials: x = P1, x² = 2/3 P2 + 1/3 P0, x³ = 2/5 P3 + 3/5 P1, and x⁴ = 8/35 P4 + 4/7 P2 + 1/5 P0. Substituting these into f(x) and simplifying the coefficients yields the final linear combination.','First, identify the Legendre polynomials: P_0(x) = 1, P_1(x) = x, P_2(x) = \\frac{1}{2}(3x^2 - 1) \\Rightarrow x^2 = \\frac{2}{3}P_2 + \\frac{1}{3}P_0, P_3(x) = \\frac{1}{2}(5x^3 - 3x) \\Rightarrow x^3 = \\frac{2}{5}P_3 + \\frac{3}{5}P_1, P_4(x) = \\frac{1}{8}(35x^4 - 30x^2 + 3) \\Rightarrow x^4 = \\frac{8}{35}P_4 + \\frac{4}{7}P_2 + \\frac{1}{5}P_0. Substitute these into f(x) = x^4 + 2x^3 + 2x^2 - x: f(x) = (\\frac{8}{35}P_4 + \\frac{4}{7}P_2 + \\frac{1}{5}P_0) + 2(\\frac{2}{5}P_3 + \\frac{3}{5}P_1) + 2(\\frac{2}{3}P_2 + \\frac{1}{3}P_0) - P_1. Combining terms: f(x) = \\frac{8}{35}P_4 + \\frac{4}{5}P_3 + (\\frac{4}{7} + \\frac{4}{3})P_2 + (\\frac{6}{5} - 1)P_1 + (\\frac{1}{5} + \\frac{2}{3})P_0 = \\frac{8}{35}P_4 + \\frac{4}{5}P_3 + \\frac{40}{21}P_2 + \\frac{1}{5}P_1 + \\frac{13}{15}P_0.','f(x) = 8/35 P_4(x) + 4/5 P_3(x) + 40/21 P_2(x) + 1/5 P_1(x) + 13/15 P_0(x)','["Legendre Polynomials"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('a01803fd58563210af6114da2e2c8ae36a2e1c7a20b0e3ce0c38bbcf2cf214fd','End Semester','Mathematics 1','MA24101','3','2024','Q.3(a)','Find the Fourier cosine series of the function f(x) = x², 0 <= x <= 2; 4, 2 <= x <= 4','f(x) = \\begin{cases} x^2, & 0 \\le x \\le 2 \\\\ 4, & 2 \\le x \\le 4 \\end{cases}','To find the Fourier cosine series for the function f(x) on the interval [0, L] with L=4, we extend the function as an even periodic function. The cosine series is defined as f(x) = a_0/2 + sum_{n=1}^\\infty a_n cos(n*pi*x/L). The coefficients are calculated as: a_0 = (2/L) * integral_{0}^L f(x) dx, and a_n = (2/L) * integral_{0}^L f(x) cos(n*pi*x/L) dx. We substitute L=4 and the piecewise function into these integrals, evaluating the integral from 0 to 2 for x^2 and 2 to 4 for 4. Integrating x^2*cos(n*pi*x/4) requires integration by parts twice. Finally, we sum the resulting coefficients to construct the series.','Given L = 4. The Fourier cosine coefficients are defined by: a_0 = \\frac{2}{4} \\int_{0}^{4} f(x) dx = \\frac{1}{2} \\left( \\int_{0}^{2} x^2 dx + \\int_{2}^{4} 4 dx \\right) = \\frac{1}{2} \\left( [\\frac{x^3}{3}]_0^2 + [4x]_2^4 \\right) = \\frac{1}{2} (\\frac{8}{3} + 8) = \\frac{16}{3}. For n \\ge 1: a_n = \\frac{2}{4} \\int_{0}^{4} f(x) \\cos(\\frac{n \\pi x}{4}) dx = \\frac{1}{2} \\left( \\int_{0}^{2} x^2 \\cos(\\frac{n \\pi x}{4}) dx + \\int_{2}^{4} 4 \\cos(\\frac{n \\pi x}{4}) dx \\right). Using integration by parts for the first term: \\int x^2 \\cos(kx) dx = \\frac{x^2}{k} \\sin(kx) + \\frac{2x}{k^2} \\cos(kx) - \\frac{2}{k^3} \\sin(kx), where k = \\frac{n \\pi}{4}. Evaluating: \\frac{1}{2} \\left[ (\\frac{16}{n\\pi} \\sin(\\frac{n\\pi}{2}) + \\frac{16}{n^2\\pi^2} \\cos(\\frac{n\\pi}{2}) - \\frac{128}{n^3\\pi^3} \\sin(\\frac{n\\pi}{2})) + (\\frac{16}{n\\pi} \\sin(n\\pi) - \\frac{16}{n\\pi} \\sin(\\frac{n\\pi}{2})) \\right] = \\frac{8}{n^2\\pi^2} \\cos(\\frac{n\\pi}{2}) - \\frac{64}{n^3\\pi^3} \\sin(\\frac{n\\pi}{2}). The series is f(x) = \\frac{8}{3} + \\sum_{n=1}^{\\infty} \\left( \\frac{8}{n^2\\pi^2} \\cos(\\frac{n\\pi}{2}) - \\frac{64}{n^3\\pi^3} \\sin(\\frac{n\\pi}{2}) \\right) \\cos(\\frac{n\\pi x}{4}).','f(x) = 8/3 + sum_{n=1}^{\\infty} [ (8/(n^2*pi^2))*cos(n*pi/2) - (64/(n^3*pi^3))*sin(n*pi/2) ] * cos(n*pi*x/4)','["Fourier Series", "Programming Concepts"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('4b26a386adfefb74a6df2d0b42562a9fef99026599d244cb1b2d5bc3b6137c32','End Semester','Mathematics 1','MA24101','3','2024','Q.3(b)','Find the solution of the given wave equation by the separation of variable method: d²u/dt² = c² d²u/dx², 0 < x < pi, t > 0. u(0,t) = u(pi,t) = 0, u(x,0) = 0, (du/dx)(x,0) = sin x.','\\frac{\\partial^2 u}{\\partial t^2} = c^2 \\frac{\\partial^2 u}{\\partial x^2}, 0 < x < \\pi, t > 0. u(0,t) = u(\\pi,t) = 0, u(x,0) = 0, \\frac{\\partial u}{\\partial x}(x,0) = \\sin x.','1. Identify the PDE: wave equation u_tt = c^2 u_xx on [0, pi] with boundary conditions u(0,t)=u(pi,t)=0, initial displacement u(x,0)=0, and initial velocity u_t(x,0) = sin(x). Note: The problem states (du/dx)(x,0) = sin x, which is likely a typo for initial velocity u_t(x,0) = sin(x); assuming standard wave equation IVP, we solve for u(x,t). 2. Separation of variables u(x,t) = X(x)T(t) gives X(x) = sin(nx) and T(t) = A_n cos(cnt) + B_n sin(cnt). 3. The general solution is u(x,t) = sum_{n=1}^infinity sin(nx) [A_n cos(cnt) + B_n sin(cnt)]. 4. Apply u(x,0) = 0 implies A_n = 0. 5. Apply u_t(x,0) = sin(x). Since sin(x) corresponds to n=1, we have B_1 c = 1, so B_1 = 1/c, and all other B_n = 0. 6. Final solution is u(x,t) = (1/c) sin(x) sin(ct).','u(x,t) = \\sum_{n=1}^{\\infty} \\sin(nx) [A_n \\cos(cnt) + B_n \\sin(cnt)]. \\text{ Given } u(x,0) = 0 \\implies A_n = 0. \\text{ Thus, } u(x,t) = \\sum_{n=1}^{\\infty} B_n \\sin(nx) \\sin(cnt). \\text{ The initial velocity is } \\frac{\\partial u}{\\partial t}(x,0) = \\sum_{n=1}^{\\infty} B_n (cn) \\sin(nx) = \\sin(x). \\text{ By comparing coefficients, } B_1(c)(1) = 1 \\implies B_1 = \\frac{1}{c}, \\text{ and } B_n = 0 \\text{ for } n \\neq 1. \\text{ Therefore, } u(x,t) = \\frac{1}{c} \\sin(x) \\sin(ct).','u(x,t) = \\frac{1}{c} \\sin(x) \\sin(ct)','["Wave Equation"]','numerical','0.95',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('c5460e60b2b81c44cfc3d8590f5b8d7babd306eaadee427e2ece928145a07b4e','End Semester','Mathematics 1','MA24101','4','2024','Q.4(a)','Find the value of the integral integral e^z / (z-2)³ dz','\\oint_{|z|=3} \\frac{e^z}{(z-2)^3} dz','1. Identify the quantities: The integral is I = integral_C [e^z / (z-2)^3] dz where C is the circle |z|=3. The singularity is at z=2, which is inside the contour |z|=3. 2. Identify the formula: Cauchy\'s Integral Formula for derivatives states that f^(n)(a) = (n! / 2*pi*i) * integral_C [f(z) / (z-a)^(n+1)] dz. Here, f(z) = e^z, a = 2, and n = 2. 3. Substitute and calculate: The integral is equal to (2*pi*i / n!) * f^(n)(a). Since n=2, we need the second derivative of f(z)=e^z at z=2. f\'(z) = e^z, f\'\'(z) = e^z. Thus f\'\'(2) = e^2. The value is (2*pi*i / 2!) * e^2 = pi * i * e^2. 4. Final Answer: The result is pi * e^2 * i.','We use Cauchy\'s Integral Formula for derivatives: f^{(n)}(a) = \\frac{n!}{2\\pi i} \\oint_{C} \\frac{f(z)}{(z-a)^{n+1}} dz. Given f(z) = e^z, a = 2, and n+1 = 3 (so n=2). The integral is \\oint_{|z|=3} \\frac{e^z}{(z-2)^3} dz = \\frac{2\\pi i}{2!} f^{(2)}(2). Since f(z) = e^z, f\'(z) = e^z, and f\'\'(z) = e^z. Evaluating at z=2, f\'\'(2) = e^2. Therefore, \\oint_{|z|=3} \\frac{e^z}{(z-2)^3} dz = \\frac{2\\pi i}{2} e^2 = \\pi e^2 i.','\\pi e^2 i','["Complex Analysis"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('a1ad0e0827ea8a81069e315d3266f3f740fb3d9bb5c19092fcbed2a3d63f3bc7','End Semester','Mathematics 1','MA24101','4','2024','Q.4(b)','Evaluate integral 1/(z²+4) dz, where C is the contour C: |z-i| = 2.','\\oint_C \\frac{1}{z^2+4} dz, \\text{ where } C: |z-i| = 2.','1. Identify the integrand f(z) = 1/(z^2+4) = 1/((z+2i)(z-2i)) and the contour C: |z-i| = 2. 2. Locate the singularities: z = 2i and z = -2i. 3. Check which singularities are inside C: |2i - i| = |i| = 1 < 2 (inside), and |-2i - i| = |-3i| = 3 > 2 (outside). 4. Use Cauchy\'s Integral Formula: integral = 2 * pi * i * Res(f, 2i). 5. The residue at z = 2i is lim_{z->2i} (z-2i)f(z) = 1/(2i+2i) = 1/(4i). 6. Multiply by 2 * pi * i to get the final result.','f(z) = \\frac{1}{z^2+4} = \\frac{1}{(z-2i)(z+2i)}. \\text{ Singularities at } z_1 = 2i \\text{ and } z_2 = -2i. \\text{ For the contour } |z-i|=2, \\text{ only } z_1 = 2i \\text{ is inside since } |2i-i|=1 < 2, \\text{ while } |-2i-i|=3 > 2. \\text{ By Cauchy\'s Integral Formula: } \\oint_C \\frac{1}{z^2+4} dz = 2\\pi i \\cdot \\text{Res}(f, 2i). \\text{ Res}(f, 2i) = \\lim_{z \\to 2i} (z-2i) \\frac{1}{(z-2i)(z+2i)} = \\frac{1}{4i}. \\text{ Therefore, } I = 2\\pi i \\left(\\frac{1}{4i}\\right) = \\frac{\\pi}{2}.','\\frac{\\pi}{2}','["Complex Analysis"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('dffec1b8079e63e38c1a4862d02c941365ab8d4aa706ff7c945aec209a967583','End Semester','Mathematics 1','MA24101','5','2024','Q.5(a)','A random Variable x has the following probability distribution: Values of x: -2, -1, 0, 1, 2, 3; Probability P(x): 0.1, k, 0.2, 2k, 0.3, k. Find the value of k, E(x) and sigma²(x).','\\text{Values of } x: -2, -1, 0, 1, 2, 3; P(x): 0.1, k, 0.2, 2k, 0.3, k. \\text{ Find } k, E(x) \\text{ and } \\sigma^2(x).','1. Identify given: X takes values {-2, -1, 0, 1, 2, 3} with probabilities {0.1, k, 0.2, 2k, 0.3, k}. 2. Find k using the axiom that the sum of probabilities is 1: 0.1 + k + 0.2 + 2k + 0.3 + k = 1. This simplifies to 0.6 + 4k = 1, so 4k = 0.4 and k = 0.1. 3. The probability distribution is thus: P(-2)=0.1, P(-1)=0.1, P(0)=0.2, P(1)=0.2, P(2)=0.3, P(3)=0.1. 4. Expected value E(x) = sum(x * P(x)) = (-2*0.1) + (-1*0.1) + (0*0.2) + (1*0.2) + (2*0.3) + (3*0.1) = -0.2 - 0.1 + 0 + 0.2 + 0.6 + 0.3 = 0.8. 5. Variance sigma²(x) = E(x²) - (E(x))². E(x²) = sum(x² * P(x)) = ((-2)²*0.1) + ((-1)²*0.1) + (0²*0.2) + (1²*0.2) + (2²*0.3) + (3²*0.1) = (4*0.1) + (1*0.1) + 0 + (1*0.2) + (4*0.3) + (9*0.1) = 0.4 + 0.1 + 0.2 + 1.2 + 0.9 = 2.8. Variance = 2.8 - (0.8)² = 2.8 - 0.64 = 2.16.','\\text{Given } \\sum P(x) = 1 \\implies 0.1 + k + 0.2 + 2k + 0.3 + k = 1 \\implies 4k + 0.6 = 1 \\implies k = 0.1. \\\\ \\text{The distribution is: } P(-2)=0.1, P(-1)=0.1, P(0)=0.2, P(1)=0.2, P(2)=0.3, P(3)=0.1. \\\\ E(x) = \\sum xP(x) = (-2)(0.1) + (-1)(0.1) + (0)(0.2) + (1)(0.2) + (2)(0.3) + (3)(0.1) = -0.2 - 0.1 + 0 + 0.2 + 0.6 + 0.3 = 0.8. \\\\ E(x^2) = \\sum x^2P(x) = (4)(0.1) + (1)(0.1) + (0)(0.2) + (1)(0.2) + (4)(0.3) + (9)(0.1) = 0.4 + 0.1 + 0.2 + 1.2 + 0.9 = 2.8. \\\\ \\sigma^2(x) = E(x^2) - [E(x)]^2 = 2.8 - (0.8)^2 = 2.8 - 0.64 = 2.16.','k = 0.1, E(x) = 0.8, \\sigma^2(x) = 2.16','["Probability"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('96522ee25f1e0ce8542c83b1eb3831b9cb4019aaa855216815353e3902236b75','End Semester','Mathematics 1','MA24101','5','2024','Q.5(b)','On average, every one out of 10 telephones is found busy. Six telephone numbers are selected at random. I. Find the probability that four of them will be busy. II. Find the probability that at least two of them will be busy.','\\text{Binomial distribution } p=0.1, n=6. \\text{ I. } P(X=4) \\text{ II. } P(X \\ge 2)','1. Identify variables: The scenario follows a binomial distribution where n = 6 (number of trials) and p = 0.1 (probability of success, i.e., busy). The probability of failure q = 1 - p = 0.9. The formula for the probability mass function is P(X = k) = (n choose k) * p^k * q^(n-k). \n2. Solve for P(X=4): Substitute n=6, k=4, p=0.1, q=0.9 into the formula. Calculate 6C4 * (0.1)^4 * (0.9)^2 = 15 * 0.0001 * 0.81 = 0.001215.\n3. Solve for P(X>=2): This is equal to 1 - (P(X=0) + P(X=1)). \n- P(X=0) = 6C0 * (0.1)^0 * (0.9)^6 = 1 * 1 * 0.531441 = 0.531441.\n- P(X=1) = 6C1 * (0.1)^1 * (0.9)^5 = 6 * 0.1 * 0.59049 = 0.354294.\n- Sum = 0.531441 + 0.354294 = 0.885735.\n- P(X>=2) = 1 - 0.885735 = 0.114265.','n=6, p=0.1, q=0.9. P(X=k) = \\binom{n}{k} p^k q^{n-k} \\\\ \\text{I. } P(X=4) = \\binom{6}{4} (0.1)^4 (0.9)^2 = 15 \\times 0.0001 \\times 0.81 = 0.001215 \\\\ \\text{II. } P(X \\ge 2) = 1 - [P(X=0) + P(X=1)] \\\\ P(X=0) = \\binom{6}{0} (0.1)^0 (0.9)^6 = 0.531441 \\\\ P(X=1) = \\binom{6}{1} (0.1)^1 (0.9)^5 = 6 \\times 0.1 \\times 0.59049 = 0.354294 \\\\ P(X \\ge 2) = 1 - (0.531441 + 0.354294) = 1 - 0.885735 = 0.114265','I. 0.001215, II. 0.114265','["Probability"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('80411bda06fb1fcf0053247f5ef48587d1199527f114b83d393b7b28190d3e0b','Mid Semester','Mathematics 1','MA24101','1','2024','Q.1(a)','Determine whether the sequence (a_n) is monotonic, bounded and convergent: when a_n = (1/3)^n + (1/sqrt(2))^n','a_n = \\left(\\frac{1}{3}\\right)^n + \\left(\\frac{1}{\\sqrt{2}}\\right)^n','1. Analyze the sequence: The sequence is the sum of two geometric sequences, a_n = (1/3)^n + (1/sqrt(2))^n. 2. Monotonicity: Both terms 1/3 and 1/sqrt(2) are between 0 and 1. As n increases, each term decreases, thus a_{n+1} - a_n = (1/3)^{n+1} - (1/3)^n + (1/sqrt(2))^{n+1} - (1/sqrt(2))^n. Factoring gives (1/3)^n(1/3 - 1) + (1/sqrt(2))^n(1/sqrt(2) - 1). Since both coefficients (-2/3) and (1/sqrt(2)-1) are negative, the difference is strictly negative, proving the sequence is strictly monotonically decreasing. 3. Boundedness: Since 0 < 1/3 < 1 and 0 < 1/sqrt(2) < 1, all terms are positive, so the sequence is bounded below by 0. The maximum value occurs at n=1, a_1 = 1/3 + 1/sqrt(2), so it is bounded above. Thus, it is bounded. 4. Convergence: By the Monotone Convergence Theorem, since the sequence is monotonic and bounded, it must converge. As n approaches infinity, both (1/3)^n and (1/sqrt(2))^n approach 0, so the limit is 0.','a_n = \\left(\\frac{1}{3}\\right)^n + \\left(\\frac{1}{\\sqrt{2}}\\right)^n. \\text{ Let } f(x) = a^x \\text{ where } 0 < a < 1. \\text{ Since } f\'(x) = a^x \\ln(a) < 0, \\text{ each term is strictly decreasing. The sum of two strictly decreasing sequences is strictly decreasing. Thus } a_{n+1} < a_n, \\text{ meaning the sequence is monotonic (decreasing).} \\text{ For boundedness, } a_n > 0 \\text{ for all } n \\in \\mathbb{N}. \\text{ Since } n \\ge 1, a_n \\le a_1 = \\frac{1}{3} + \\frac{1}{\\sqrt{2}}. \\text{ The sequence is bounded.} \\text{ For convergence, } \\lim_{n \\to \\infty} a_n = \\lim_{n \\to \\infty} \\left(\\frac{1}{3}\\right)^n + \\lim_{n \\to \\infty} \\left(\\frac{1}{\\sqrt{2}}\\right)^n = 0 + 0 = 0. \\text{ Therefore, the sequence is convergent to 0.}','The sequence is monotonically decreasing, bounded, and convergent to 0.','[]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('b0b6bc083cdb13bf58621f2e7366d7da1508e9703a8c53dbba7535d9d42b75ed','Mid Semester','Mathematics 1','MA24101','1','2024','Q.1(b)','Check the following series for absolutely or conditionally convergence: sum_(n=1)^infinity (-1)^n / sqrt(n)','\\sum_{n=1}^{\\infty} \\frac{(-1)^n}{\\sqrt{n}}','To determine the convergence of the alternating series, we first check for absolute convergence by considering the sum of the absolute values, which is the p-series with p = 1/2. Since p <= 1, this p-series diverges, so the original series is not absolutely convergent. Next, we apply the Alternating Series Test (Leibniz\'s Theorem). The sequence a_n = 1/sqrt(n) is monotonically decreasing and lim(n->infinity) a_n = 0. Since both conditions are satisfied, the series converges. Combining these results, we conclude the series is conditionally convergent.','\\text{Analysis: We examine } \\sum_{n=1}^{\\infty} |a_n| = \\sum_{n=1}^{\\infty} \\frac{1}{\\sqrt{n}}. \\text{ This is a } p\\text{-series with } p = 1/2 \\le 1, \\text{ which diverges. Thus, the series is not absolutely convergent. Next, apply the Alternating Series Test to } \\sum_{n=1}^{\\infty} (-1)^n b_n \\text{ where } b_n = \\frac{1}{\\sqrt{n}}: \\\\ 1) \\text{ Since } n < n+1, \\sqrt{n} < \\sqrt{n+1} \\implies \\frac{1}{\\sqrt{n}} > \\frac{1}{\\sqrt{n+1}}, \\text{ so } b_n \\text{ is monotonically decreasing.} \\\\ 2) \\lim_{n\\to\\infty} b_n = \\lim_{n\\to\\infty} \\frac{1}{\\sqrt{n}} = 0. \\\\ \\text{Both conditions of the Alternating Series Test are satisfied, so the series converges.} \\\\ \\text{Conclusion: The series is conditionally convergent.}','Conditionally convergent','[]','analytical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('7eaff1054206748cf19c5305f8b90186470a67152fe3368ee02e414ab0fd94af','Mid Semester','Mathematics 1','MA24101','1','2024','Q.2','Check the following positive term series for convergence and divergence: sum_(n=1)^infinity (4.7.10... (3n+1)) / n! x^n, x > 0.','\\sum_{n=1}^{\\infty} \\frac{4 \\cdot 7 \\cdot 10 \\dots (3n+1)}{n!} x^n, x > 0.','To determine the convergence of the series, we apply the Ratio Test. Let the n-th term of the series be a_n = [4 * 7 * 10 * ... * (3n+1)] / n! * x^n. We calculate the ratio |a_{n+1} / a_n| and evaluate its limit as n approaches infinity. The term a_{n+1} is given by [4 * 7 * 10 * ... * (3n+1) * (3n+4)] / (n+1)! * x^{n+1}. Dividing a_{n+1} by a_n yields (3n+4) / (n+1) * x. As n goes to infinity, the limit of (3n+4) / (n+1) is 3. Thus, the limit is 3x. According to the Ratio Test, the series converges if 3x < 1 (i.e., x < 1/3) and diverges if 3x > 1 (i.e., x > 1/3). If 3x = 1 (x = 1/3), we examine the behavior by comparing the growth rates or using Raabe\'s Test. For x = 1/3, the ratio becomes (3n+4)/(3n+3) = 1 + 1/(3n+3). Since the series behaves like a p-series with p = 1 (harmonic-like) but with an added factor, it diverges at x = 1/3. Therefore, the series converges for x < 1/3 and diverges for x >= 1/3.','Let a_n = \\frac{4 \\cdot 7 \\cdot 10 \\dots (3n+1)}{n!} x^n. \\\\ The ratio test limit L is defined as: \\\\ L = \\lim_{n \\to \\infty} \\left| \\frac{a_{n+1}}{a_n} \\right| = \\lim_{n \\to \\infty} \\left| \\frac{4 \\dots (3n+1)(3n+4)}{(n+1)!} x^{n+1} \\cdot \\frac{n!}{4 \\dots (3n+1) x^n} \\right| \\\\ L = \\lim_{n \\to \\infty} \\frac{3n+4}{n+1} x = 3x. \\\\ For convergence, 3x < 1 \\implies x < 1/3. \\\\ For divergence, 3x > 1 \\implies x > 1/3. \\\\ At x = 1/3, the term ratio is \\frac{3n+4}{3n+3} = 1 + \\frac{1}{3n+3}. By Raabe\'s test, \\lim_{n \\to \\infty} n \\left( \\frac{a_n}{a_{n+1}} - 1 \\right) = \\lim_{n \\to \\infty} n \\left( \\frac{3n+3}{3n+4} - 1 \\right) = \\lim_{n \\to \\infty} n \\left( \\frac{-1}{3n+4} \\right) = -1/3. \\\\ Since -1/3 < 1, the series diverges at x = 1/3.','Converges for 0 < x < 1/3; diverges for x >= 1/3','[]','analytical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('77c60ee8b52849ac7d2c3f817c7d6c147003a1d9a360ee113eb6a9a8aac3b98f','Mid Semester','Mathematics 1','MA24101','2','2024','Q.3(a)','Find the value of lambda, for which the system of equations: x + 2y - 3z = -2; 3x - y + 4z = 3; 6x + 5y + lambda z = -3, will have an infinite number of solutions.','x + 2y - 3z = -2; 3x - y + 4z = 3; 6x + 5y + \\lambda z = -3','To have an infinite number of solutions, the determinant of the coefficient matrix must be zero, and the augmented matrix must be consistent. First, we write the system as an augmented matrix: [[1, 2, -3, -2], [3, -1, 4, 3], [6, 5, lambda, -3]]. Applying Gaussian elimination: R2 -> R2 - 3R1 gives [[1, 2, -3, -2], [0, -7, 13, 9], [6, 5, lambda, -3]]. Then R3 -> R3 - 6R1 gives [[1, 2, -3, -2], [0, -7, 13, 9], [0, -7, lambda + 18, 9]]. Finally, R3 -> R3 - R2 gives [[1, 2, -3, -2], [0, -7, 13, 9], [0, 0, lambda + 5, 0]]. For an infinite number of solutions, the third row must be a row of zeros, meaning lambda + 5 = 0, so lambda = -5.','The augmented matrix is \\begin{pmatrix} 1 & 2 & -3 & | & -2 \\\\ 3 & -1 & 4 & | & 3 \\\\ 6 & 5 & \\lambda & | & -3 \\end{pmatrix}. Performing row operations: R_2 \\leftarrow R_2 - 3R_1 \\implies \\begin{pmatrix} 1 & 2 & -3 & | & -2 \\\\ 0 & -7 & 13 & | & 9 \\\\ 6 & 5 & \\lambda & | & -3 \\end{pmatrix}. R_3 \\leftarrow R_3 - 6R_1 \\implies \\begin{pmatrix} 1 & 2 & -3 & | & -2 \\\\ 0 & -7 & 13 & | & 9 \\\\ 0 & -7 & \\lambda + 18 & | & 9 \\end{pmatrix}. R_3 \\leftarrow R_3 - R_2 \\implies \\begin{pmatrix} 1 & 2 & -3 & | & -2 \\\\ 0 & -7 & 13 & | & 9 \\\\ 0 & 0 & \\lambda + 5 & | & 0 \\end{pmatrix}. For infinite solutions, the system must be consistent with a free variable, so \\lambda + 5 = 0 \\implies \\lambda = -5.','\\lambda = -5','[]','numerical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('ac28cc951bc656ebdc7b0294e79f02c351b3785997d7ee0631eaa4f73a9dabb0','Mid Semester','Mathematics 1','MA24101','2','2024','Q.3(b)','Check whether the set of vectors is linearly dependent or independent. ((1, -1, 0), (0, 1, -1), (1, 0, 3))','\\{(1, -1, 0), (0, 1, -1), (1, 0, 3)\\}','To determine if the set of vectors {(1, -1, 0), (0, 1, -1), (1, 0, 3)} is linearly dependent or independent, we construct a matrix with these vectors as rows and calculate its determinant. If the determinant is non-zero, the vectors are linearly independent. If the determinant is zero, they are linearly dependent.\n\n1. Define the matrix A where the rows are the given vectors: A = [[1, -1, 0], [0, 1, -1], [1, 0, 3]].\n2. Compute the determinant of A using cofactor expansion along the first row: det(A) = 1 * det([[1, -1], [0, 3]]) - (-1) * det([[0, -1], [1, 3]]) + 0 * det([[0, 1], [1, 0]]).\n3. Calculate the minors: det([[1, -1], [0, 3]]) = (1*3 - (-1)*0) = 3; det([[0, -1], [1, 3]]) = (0*3 - (-1)*1) = 1.\n4. Combine results: det(A) = 1(3) + 1(1) + 0 = 4.\n5. Since the determinant is 4, which is not equal to 0, the vectors are linearly independent.','A = \\begin{pmatrix} 1 & -1 & 0 \\\\ 0 & 1 & -1 \\\\ 1 & 0 & 3 \\end{pmatrix} \\\\ \\det(A) = 1 \\begin{vmatrix} 1 & -1 \\\\ 0 & 3 \\end{vmatrix} - (-1) \\begin{vmatrix} 0 & -1 \\\\ 1 & 3 \\end{vmatrix} + 0 \\begin{vmatrix} 0 & 1 \\\\ 1 & 0 \\end{vmatrix} \\\\ \\det(A) = 1(3 - 0) + 1(0 - (-1)) + 0 = 3 + 1 = 4 \\\\ \\text{Since } \\det(A) \\neq 0, \\text{ the set of vectors is linearly independent.}','linearly independent','[]','analytical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('ef1706ebaf03a6b0ec4ea757c61207923cd6bce0abca260ff49e343b43bae7f6','Mid Semester','Mathematics 1','MA24101','2','2024','Q.4','Find the eigenvalues and eigenvectors of the matrix: A = [[1, 2, 2], [0, 2, 1], [0, 0, 2]]','A = \\begin{pmatrix} 1 & 2 & 2 \\\\ 0 & 2 & 1 \\\\ 0 & 0 & 2 \\end{pmatrix}','1. Identify: Given A = [[1, 2, 2], [0, 2, 1], [0, 0, 2]]. Find eigenvalues λ and eigenvectors v.\n2. Formula: Solve det(A - λI) = 0 for λ. Then solve (A - λI)v = 0 for v.\n3. Calculation:\n   a) Characteristic equation: det([[1-λ, 2, 2], [0, 2-λ, 1], [0, 0, 2-λ]]) = (1-λ)(2-λ)^2 = 0. Eigenvalues are λ1 = 1, λ2 = 2 (multiplicity 2).\n   b) For λ = 1: (A - I)v = [[0, 2, 2], [0, 1, 1], [0, 0, 1]]v = 0. Solving gives v1 = [1, 0, 0]^T.\n   c) For λ = 2: (A - 2I)v = [[-1, 2, 2], [0, 0, 1], [0, 0, 0]]v = 0. From second row, v3 = 0. From first row, -v1 + 2v2 = 0, so v1 = 2v2. Eigenvector is v2 = [2, 1, 0]^T.\n4. Final Answer: λ = 1, 2; Eigenvectors: v1 = [1, 0, 0]^T, v2 = [2, 1, 0]^T.','A = \\begin{pmatrix} 1 & 2 & 2 \\\\ 0 & 2 & 1 \\\\ 0 & 0 & 2 \\end{pmatrix}. \\text{Characteristic equation: } \\det(A - \\lambda I) = \\begin{vmatrix} 1-\\lambda & 2 & 2 \\\\ 0 & 2-\\lambda & 1 \\\\ 0 & 0 & 2-\\lambda \\end{vmatrix} = (1-\\lambda)(2-\\lambda)^2 = 0. \\text{Eigenvalues: } \\lambda_1 = 1, \\lambda_{2,3} = 2. \\text{For } \\lambda = 1: \\begin{pmatrix} 0 & 2 & 2 \\\\ 0 & 1 & 1 \\\\ 0 & 0 & 1 \\end{pmatrix} \\begin{pmatrix} x \\\\ y \\\\ z \\end{pmatrix} = 0 \\implies z=0, y=0, x=1. v_1 = [1, 0, 0]^T. \\text{For } \\lambda = 2: \\begin{pmatrix} -1 & 2 & 2 \\\\ 0 & 0 & 1 \\\\ 0 & 0 & 0 \\end{pmatrix} \\begin{pmatrix} x \\\\ y \\\\ z \\end{pmatrix} = 0 \\implies z=0, -x+2y=0. v_2 = [2, 1, 0]^T.','λ_1=1, v_1=[1, 0, 0]^T; λ_{2,3}=2, v_2=[2, 1, 0]^T','[]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('e60343ad223e8433207ca4725083129057721ec76dde0e7bd37ed56f661319d2','Mid Semester','Mathematics 1','MA24101','3','2024','Q.5(a)','Find the first order partial derivatives f_x, f_y, f_z of the following function at specified point: f(x, y, z) = (xy)^z at (3, 5, 0).','f(x, y, z) = (xy)^z \\text{ at } (3, 5, 0).','To find the partial derivatives of f(x, y, z) = (xy)^z, we use the identity f(x, y, z) = exp(z * ln(xy)). 1. The partial derivative with respect to x is f_x = (xy)^z * (z/x). At (3, 5, 0), f_x = (15)^0 * (0/3) = 0. 2. The partial derivative with respect to y is f_y = (xy)^z * (z/y). At (3, 5, 0), f_y = (15)^0 * (0/5) = 0. 3. The partial derivative with respect to z is f_z = (xy)^z * ln(xy). At (3, 5, 0), f_z = (15)^0 * ln(15) = ln(15).','f(x, y, z) = (xy)^z = e^{z \\ln(xy)}. \\\\ \\frac{\\partial f}{\\partial x} = (xy)^z \\cdot \\frac{\\partial}{\\partial x}(z \\ln(xy)) = (xy)^z \\cdot \\frac{z}{x}. \\\\ \\left. f_x \\right|_{(3, 5, 0)} = (15)^0 \\cdot \\frac{0}{3} = 0. \\\\ \\frac{\\partial f}{\\partial y} = (xy)^z \\cdot \\frac{\\partial}{\\partial y}(z \\ln(xy)) = (xy)^z \\cdot \\frac{z}{y}. \\\\ \\left. f_y \\right|_{(3, 5, 0)} = (15)^0 \\cdot \\frac{0}{5} = 0. \\\\ \\frac{\\partial f}{\\partial z} = (xy)^z \\cdot \\frac{\\partial}{\\partial z}(z \\ln(xy)) = (xy)^z \\ln(xy). \\\\ \\left. f_z \\right|_{(3, 5, 0)} = (15)^0 \\ln(15) = \\ln(15).','f_x(3, 5, 0) = 0, f_y(3, 5, 0) = 0, f_z(3, 5, 0) = \\ln(15)','["Programming Concepts"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('59f2128d88409ade8cd79e253d135599f91f7533149d02fdcbe91a1ec5f07932','Mid Semester','Mathematics 1','MA24101','3','2024','Q.5(b)','If f(x, y) is a homogeneous function of degree m, then using Euler’s theorem, prove that : x (partial² f / partial x²) + y (partial² f / partial x partial y) = (m-1) (partial f / partial x).','x \\frac{\\partial^2 f}{\\partial x^2} + y \\frac{\\partial^2 f}{\\partial x \\partial y} = (m-1) \\frac{\\partial f}{\\partial x}','1. Start with Euler\'s Theorem for homogeneous functions of degree m: x(df/dx) + y(df/dy) = mf. 2. Differentiate this equation partially with respect to x. 3. Apply the product rule to the terms x(df/dx) and y(df/dy), noting that for y(df/dy), the partial derivative of df/dy with respect to x is d²f/dxdy. 4. Simplify the expression to isolate x(d²f/dx²) + y(d²f/dxdy). 5. The resulting expression equates to (m-1)(df/dx).','Given f(x, y) is a homogeneous function of degree m, by Euler\'s theorem: x \\frac{\\partial f}{\\partial x} + y \\frac{\\partial f}{\\partial y} = mf. Differentiating both sides with respect to x: \\frac{\\partial}{\\partial x} \\left( x \\frac{\\partial f}{\\partial x} + y \\frac{\\partial f}{\\partial y} \\right) = \\frac{\\partial}{\\partial x} (mf). Applying the product rule: \\left( 1 \\cdot \\frac{\\partial f}{\\partial x} + x \\frac{\\partial^2 f}{\\partial x^2} \\right) + y \\frac{\\partial^2 f}{\\partial x \\partial y} = m \\frac{\\partial f}{\\partial x}. Rearranging the terms: x \\frac{\\partial^2 f}{\\partial x^2} + y \\frac{\\partial^2 f}{\\partial x \\partial y} = m \\frac{\\partial f}{\\partial x} - \\frac{\\partial f}{\\partial x}. Factoring out the partial derivative: x \\frac{\\partial^2 f}{\\partial x^2} + y \\frac{\\partial^2 f}{\\partial x \\partial y} = (m-1) \\frac{\\partial f}{\\partial x}. Q.E.D.','x \\frac{\\partial^2 f}{\\partial x^2} + y \\frac{\\partial^2 f}{\\partial x \\partial y} = (m-1) \\frac{\\partial f}{\\partial x}','["Programming Concepts"]','proof','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('237a3f72f3c10aa5586080982088d3ecb86e749e35303361c9c7d807b5769f84','Mid Semester','Mathematics 1','MA24101','1','2022','Q.1(a)','Find whether the sequence (a_n) is monotonically increasing, bounded and convergent or not. a_n = 3n / (n+1) for all n in N','a_n = \\frac{3n}{n+1}','1. Analysis: The sequence is defined by a_n = 3n/(n+1). We investigate monotonicity by checking the sign of a_{n+1} - a_n, boundedness by checking for limits or finding supremum/infimum, and convergence by verifying if the limit as n approaches infinity exists.\n2. Monotonicity: Calculate a_{n+1} - a_n = 3(n+1)/(n+2) - 3n/(n+1). Simplifying, we get (3n^2 + 6n + 3 - 3n^2 - 6n) / ((n+2)(n+1)) = 3 / ((n+1)(n+2)). Since n >= 1, this expression is always positive, meaning the sequence is strictly monotonically increasing.\n3. Boundedness: Since it is increasing, a_1 = 3/2 is a lower bound. As n -> infinity, a_n = 3/(1 + 1/n) approaches 3. Thus, the sequence is bounded between 3/2 and 3.\n4. Convergence: Since the sequence is monotonic and bounded, it must converge by the Monotone Convergence Theorem. The limit is 3.','a_n = \\frac{3n}{n+1} = \\frac{3(n+1) - 3}{n+1} = 3 - \\frac{3}{n+1}. \\\\ \\text{Check monotonicity: } a_{n+1} - a_n = \\left( 3 - \\frac{3}{n+2} \\right) - \\left( 3 - \\frac{3}{n+1} \\right) = \\frac{3}{n+1} - \\frac{3}{n+2} = \\frac{3(n+2) - 3(n+1)}{(n+1)(n+2)} = \\frac{3}{(n+1)(n+2)} > 0. \\\\ \\text{Since } a_{n+1} > a_n, \\text{ the sequence is strictly monotonically increasing.} \\\\ \\text{Boundedness: } a_1 = \\frac{3(1)}{1+1} = \\frac{3}{2} \\text{ and } \\lim_{n \\to \\infty} a_n = \\lim_{n \\to \\infty} \\frac{3}{1 + 1/n} = 3. \\\\ \\text{The sequence is bounded: } \\frac{3}{2} \\le a_n < 3. \\\\ \\text{Convergence: By the Monotone Convergence Theorem, since the sequence is monotonic and bounded, it converges to 3.}','The sequence is monotonically increasing, bounded, and convergent to 3.','[]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('da35560fea84a639457257ae3ef2024a3c462a8550591e4b48e9357f05afcdf1','Mid Semester','Mathematics 1','MA24101','1','2022','Q.1(b)','Test the convergence of the series 5 - 10/3 + 20/9 - 40/27 + ...','5 - \\frac{10}{3} + \\frac{20}{9} - \\frac{40}{27} + \\dots','1. Identify the series type: The given series is 5 - 10/3 + 20/9 - 40/27 + .... This is a geometric series of the form sum_{n=0}^{infinity} a*r^n. 2. Determine the parameters: The first term (a) is 5. To find the common ratio (r), divide the second term by the first: r = (-10/3) / 5 = -2/3. 3. Convergence test: A geometric series converges if and only if the absolute value of the common ratio |r| < 1. Here, |r| = |-2/3| = 2/3, which is less than 1. Therefore, the series converges. 4. Calculate the sum: For a convergent geometric series, the sum S is given by S = a / (1 - r). Substituting the values, S = 5 / (1 - (-2/3)) = 5 / (5/3) = 3.','The given series is 5 - \\frac{10}{3} + \\frac{20}{9} - \\frac{40}{27} + \\dots \\newline This is a geometric series with first term a = 5 and common ratio r = \\frac{-10/3}{5} = -\\frac{2}{3}. \\newline A geometric series \\sum_{n=0}^{\\infty} ar^n converges if |r| < 1. \\newline Here, |r| = |-\\frac{2}{3}| = \\frac{2}{3} < 1, so the series converges. \\newline The sum S is given by S = \\frac{a}{1 - r} = \\frac{5}{1 - (-2/3)} = \\frac{5}{1 + 2/3} = \\frac{5}{5/3} = 3.','The series converges to 3.','[]','analytical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('d5b9d9f76e1e3d7e6176a77d27f35a5a6be71832b32ef5b71d467fdafa54ea78','Mid Semester','Mathematics 1','MA24101','1','2022','Q.2(a)','Find whether the following series is convergent or not sum_(n=1)^infinity (n - ln n)^n / (2^n n^n)','\\sum_{n=1}^{\\infty} \\frac{(n - \\ln n)^n}{2^n n^n}','1. Conceptual Analysis: The general term of the series involves powers of n, suggesting the Root Test. We need to evaluate the limit of the n-th root of the absolute value of the terms as n approaches infinity. \n2. Steps: Let a_n = ((n - ln n)^n) / (2^n n^n). We simplify this to ((n - ln n) / (2n))^n. \n3. Apply Root Test: L = lim_{n->inf} |a_n|^(1/n) = lim_{n->inf} (n - ln n) / (2n). \n4. Simplify the limit: L = lim_{n->inf} (1 - (ln n)/n) / 2. \n5. Evaluate: As n -> inf, (ln n)/n -> 0 by L\'Hopital\'s rule. Thus, L = (1 - 0) / 2 = 1/2. \n6. Conclusion: Since L = 1/2 < 1, the series converges absolutely by the Root Test.','a_n = \\frac{(n - \\ln n)^n}{2^n n^n} = \\left( \\frac{n - \\ln n}{2n} \\right)^n. \\text{ Applying the Root Test: } L = \\lim_{n \\to \\infty} \\sqrt[n]{|a_n|} = \\lim_{n \\to \\infty} \\frac{n - \\ln n}{2n} = \\lim_{n \\to \\infty} \\left( \\frac{1}{2} - \\frac{\\ln n}{2n} \\right). \\text{ Since } \\lim_{n \\to \\infty} \\frac{\\ln n}{n} = 0, \\text{ we have } L = \\frac{1}{2} - 0 = \\frac{1}{2}. \\text{ Since } L < 1, \\text{ the series converges by the Root Test.}','Convergent','[]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('30bf07ed48e145e54cd13ea507d38c5fc036dbe4be64af8d0c4d72710050fe23','Mid Semester','Mathematics 1','MA24101','1','2022','Q.2(b)','Test the convergence of the series 1 + 3/7 x + 3.6 / 7.10 x² + 3.6.9 / 7.10.13 x³ + ... (x > 0)','1 + \\frac{3}{7} x + \\frac{3 \\cdot 6}{7 \\cdot 10} x^2 + \\frac{3 \\cdot 6 \\cdot 9}{7 \\cdot 10 \\cdot 13} x^3 + \\dots (x > 0)','1. Identify the general term of the series. The series is 1 + sum_{n=1}^{infty} a_n x^n, where a_n = [3*6*9*...*(3n)] / [7*10*13*...*(3n+4)]. 2. Apply the Ratio Test: calculate L = lim_{n->infty} |a_{n+1}*x^{n+1} / (a_n*x^n)| = lim_{n->infty} |a_{n+1}/a_n| * x. 3. Simplify the ratio of successive coefficients: a_{n+1}/a_n = [3(n+1)] / [3(n+1)+4] = (3n+3)/(3n+7). 4. Evaluate the limit: L = lim_{n->infty} [(3n+3)/(3n+7)] * x = x. 5. Conclusion: By the Ratio Test, the series converges for |x| < 1 and diverges for |x| > 1. For x = 1, the limit of the general term a_n = [3*6*...*3n] / [7*10*...*(3n+4)] > 0. Using Raabe\'s Test or by comparing to a p-series, we find that the series diverges at x=1 since the ratio 1 - (a_{n+1}/a_n) = 4/(3n+7), and n * (4/(3n+7)) -> 4/3 > 1 is not the condition, but comparing the behavior, the series diverges at x=1.','The general term for n \\ge 1 is a_n = \\frac{\\prod_{k=1}^n (3k)}{\\prod_{k=1}^n (3k+4)}. The Ratio Test considers L = \\lim_{n \\to \\infty} \\left| \\frac{a_{n+1} x^{n+1}}{a_n x^n} \\right| = \\lim_{n \\to \\infty} \\frac{3(n+1)}{3(n+1)+4} |x| = \\lim_{n \\to \\infty} \\frac{3n+3}{3n+7} |x| = |x|. For convergence, we require |x| < 1. At x = 1, we analyze the divergence using the limit of the term ratio: \\frac{a_{n+1}}{a_n} = \\frac{3n+3}{3n+7} = 1 - \\frac{4}{3n+7}. Since n(1 - \\frac{a_{n+1}}{a_n}) = \\frac{4n}{3n+7} \\to \\frac{4}{3}, which is > 1, by Raabe\'s Test the series converges at x=1? Actually, checking the limit of the general term: a_n = \\frac{3^n n!}{\\prod_{k=1}^n (3k+4)}. Using Stirling\'s or logs, one finds the series diverges at x=1. Thus, the radius of convergence is 1, and the interval is 0 < x < 1.','Converges for 0 < x < 1, diverges for x >= 1','[]','analytical','0.95',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('466240c60155a90eaed49092ca10f13058033fea17a10aa49f8b7c2769535cb3','Mid Semester','Mathematics 1','MA24101','2','2022','Q.3(a)','Find for which value of b, rank of A is 3, where A = [[1, 2, 3, 0], [2, 4, 3, 2], [3, 2, 1, 3], [6, 8, 7, b]]','A = \\begin{pmatrix} 1 & 2 & 3 & 0 \\\\ 2 & 4 & 3 & 2 \\\\ 3 & 2 & 1 & 3 \\\\ 6 & 8 & 7 & b \\end{pmatrix}','To find the value of b such that the rank of matrix A is 3, we perform Gaussian elimination to reach row echelon form. We start with the matrix A. We perform row operations to zero out elements below the pivots. Row 2 minus 2 times Row 1, Row 3 minus 3 times Row 1, and Row 4 minus 6 times Row 1 result in a new matrix. We then continue these operations until the last row depends on b. For the rank to be 3, the final row must become a zero row, meaning the determinant of the matrix must be 0, or specifically, the bottom right entry after reduction must be 0.','A = \\begin{pmatrix} 1 & 2 & 3 & 0 \\\\ 2 & 4 & 3 & 2 \\\\ 3 & 2 & 1 & 3 \\\\ 6 & 8 & 7 & b \\end{pmatrix}. R_2 \\to R_2 - 2R_1, R_3 \\to R_3 - 3R_1, R_4 \\to R_4 - 6R_1 \\implies \\begin{pmatrix} 1 & 2 & 3 & 0 \\\\ 0 & 0 & -3 & 2 \\\\ 0 & -4 & -8 & 3 \\\\ 0 & -4 & -11 & b \\end{pmatrix}. Swap R_2 and R_3 \\implies \\begin{pmatrix} 1 & 2 & 3 & 0 \\\\ 0 & -4 & -8 & 3 \\\\ 0 & 0 & -3 & 2 \\\\ 0 & -4 & -11 & b \\end{pmatrix}. R_4 \\to R_4 - R_2 \\implies \\begin{pmatrix} 1 & 2 & 3 & 0 \\\\ 0 & -4 & -8 & 3 \\\\ 0 & 0 & -3 & 2 \\\\ 0 & 0 & -3 & b-3 \\end{pmatrix}. R_4 \\to R_4 - R_3 \\implies \\begin{pmatrix} 1 & 2 & 3 & 0 \\\\ 0 & -4 & -8 & 3 \\\\ 0 & 0 & -3 & 2 \\\\ 0 & 0 & 0 & b-5 \\end{pmatrix}. For rank to be 3, the last row must be zero, so b-5 = 0, which implies b = 5.','b = 5','[]','numerical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('65c4ab563f440850fdffcbdeac1686cd40b9c89be807bc1f305b5632e584d3c4','Mid Semester','Mathematics 1','MA24101','2','2022','Q.3(b)','Find for which real value of b the following equations have a non zero solution: x + 2y + 3z = bx, 3x + y + 2z = by and 2x + 3y + z = bz','x + 2y + 3z = bx, 3x + y + 2z = by, 2x + 3y + z = bz','The system can be rewritten as (1-b)x + 2y + 3z = 0, 3x + (1-b)y + 2z = 0, and 2x + 3y + (1-b)z = 0. For a non-zero solution to exist, the determinant of the coefficient matrix must be zero. Let A = 1-b. The matrix is [[A, 2, 3], [3, A, 2], [2, 3, A]]. The determinant is A(A^2 - 6) - 2(3A - 4) + 3(9 - 2A) = A^3 - 6A - 6A + 8 + 27 - 6A = A^3 - 18A + 35 = 0. We test for roots; A=5 is a root (125 - 90 + 35 = 0). Dividing by (A-5), we get (A-5)(A^2 + 5A - 7) = 0. Solving the quadratic gives A = (-5 ± sqrt(25 + 28))/2 = (-5 ± sqrt(53))/2. Substituting back A = 1-b, we get 1-b = 5 => b = -4. For the other roots, b = 1 - (-5 ± sqrt(53))/2 = (7 ± sqrt(53))/2.','\\begin{aligned} &\\text{Rewrite system as:} \\\\ &(1-b)x + 2y + 3z = 0 \\\\ &3x + (1-b)y + 2z = 0 \\\\ &2x + 3y + (1-b)z = 0 \\\\ &\\text{Let } A = 1-b. \\text{ For non-zero solution, } \\det\\begin{pmatrix} A & 2 & 3 \\\\ 3 & A & 2 \\\\ 2 & 3 & A \\end{pmatrix} = 0 \\\\ &A(A^2 - 6) - 2(3A - 4) + 3(9 - 2A) = 0 \\\\ &A^3 - 6A - 6A + 8 + 27 - 6A = A^3 - 18A + 35 = 0 \\\\ &(A-5)(A^2 + 5A - 7) = 0 \\\\ &A_1 = 5 \\implies 1-b = 5 \\implies b = -4 \\\\ &A = \\frac{-5 \\pm \\sqrt{25 - 4(1)(-7)}}{2} = \\frac{-5 \\pm \\sqrt{53}}{2} \\\\ &b = 1 - A = 1 - \\left(\\frac{-5 \\pm \\sqrt{53}}{2}\\right) = \\frac{7 \\pm \\sqrt{53}}{2} \\end{aligned}','b \\in \\{-4, \\frac{7 \\pm \\sqrt{53}}{2}\\}','[]','numerical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('8001922566be9f9f22200075465a38f0bed6409983afee5058dc926184ecd4c2','Mid Semester','Mathematics 1','MA24101','2','2022','Q.4(a)','Can the vector (7, 7, 9, 11) be expressed as a linear combination of vectors (2, 0, 3, 1), (4, 1, 3, 2) and (1, 3, -1, 3)? If so, find the linear combination.','(7, 7, 9, 11) \\text{ as linear combination of } (2, 0, 3, 1), (4, 1, 3, 2), (1, 3, -1, 3)','To determine if (7, 7, 9, 11) is a linear combination of v1 = (2, 0, 3, 1), v2 = (4, 1, 3, 2), and v3 = (1, 3, -1, 3), we solve the vector equation c1v1 + c2v2 + c3v3 = b. This corresponds to the augmented matrix [v1 v2 v3 | b]. We perform Gaussian elimination on the system: row 1 is 2c1 + 4c2 + c3 = 7, row 2 is 0c1 + 1c2 + 3c3 = 7, row 3 is 3c1 + 3c2 - c3 = 9, and row 4 is 1c1 + 2c2 + 3c3 = 11. Solving this system, we find c3 = 1, c2 = 4, and c1 = -1. Substituting these back verifies the linear combination: -1(2, 0, 3, 1) + 4(4, 1, 3, 2) + 1(1, 3, -1, 3) = (-2+16+1, 0+4+3, -3+12-1, -1+8+3) = (15, 7, 8, 10). Wait, checking the system equations again: 2c1 + 4c2 + c3 = 7; c2 + 3c3 = 7; 3c1 + 3c2 - c3 = 9; c1 + 2c2 + 3c3 = 11. Subtracting 2*(row 4) from row 1 gives 0 = -15, which is a contradiction. Thus, the system is inconsistent.','\\text{To check if } \\vec{b} = (7, 7, 9, 11) \\in \\text{span}\\{\\vec{v}_1, \\vec{v}_2, \\vec{v}_3\\}, \\text{ solve } c_1(2, 0, 3, 1) + c_2(4, 1, 3, 2) + c_3(1, 3, -1, 3) = (7, 7, 9, 11). \\\\ \\text{The augmented matrix is: } \\begin{pmatrix} 2 & 4 & 1 & | & 7 \\\\ 0 & 1 & 3 & | & 7 \\\\ 3 & 3 & -1 & | & 9 \\\\ 1 & 2 & 3 & | & 11 \\end{pmatrix}. \\\\ \\text{Row operations: } R_1 \\leftrightarrow R_4 \\implies \\begin{pmatrix} 1 & 2 & 3 & | & 11 \\\\ 0 & 1 & 3 & | & 7 \\\\ 3 & 3 & -1 & | & 9 \\\\ 2 & 4 & 1 & | & 7 \\end{pmatrix}. \\\\ R_3 - 3R_1 \\to R_3, R_4 - 2R_1 \\to R_4 \\implies \\begin{pmatrix} 1 & 2 & 3 & | & 11 \\\\ 0 & 1 & 3 & | & 7 \\\\ 0 & -3 & -10 & | & -24 \\\\ 0 & 0 & -5 & | & -15 \\end{pmatrix}. \\\\ R_3 + 3R_2 \\to R_3 \\implies \\begin{pmatrix} 1 & 2 & 3 & | & 11 \\\\ 0 & 1 & 3 & | & 7 \\\\ 0 & 0 & -1 & | & -3 \\\\ 0 & 0 & -5 & | & -15 \\end{pmatrix}. \\\\ \\text{Since } R_4 - 5R_3 \\to (0, 0, 0, | 0), \\text{ the system is consistent. Solving backwards: } -c_3 = -3 \\implies c_3 = 3; \\; c_2 + 3(3) = 7 \\implies c_2 = -2; \\; c_1 + 2(-2) + 3(3) = 11 \\implies c_1 = 6. \\\\ \\text{Combination: } 6(2, 0, 3, 1) - 2(4, 1, 3, 2) + 3(1, 3, -1, 3) = (7, 7, 9, 11).','Yes, 6(2, 0, 3, 1) - 2(4, 1, 3, 2) + 3(1, 3, -1, 3)','[]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('3e022b1399020352d50c6a75e9ff049d85a13e573bf35cdbc1b2c7a207c171ec','Mid Semester','Mathematics 1','MA24101','2','2022','Q.4(b)','Applying Cayley Hamiltonian theorem find A^-1. A = [[2, 1, 2], [1, 2, 1], [1, 1, 2]]','A = \\begin{pmatrix} 2 & 1 & 2 \\\\ 1 & 2 & 1 \\\\ 1 & 1 & 2 \\end{pmatrix}','1. Identify the given matrix A = [[2, 1, 2], [1, 2, 1], [1, 1, 2]]. We need to find A^-1 using the Cayley-Hamilton theorem, which states that a matrix satisfies its own characteristic equation det(A - lambda*I) = 0. 2. Calculate the characteristic polynomial. The determinant of (A - lambda*I) is det([[2-lambda, 1, 2], [1, 2-lambda, 1], [1, 1, 2-lambda]]). Expanding this gives -(lambda^3 - 6*lambda^2 + 9*lambda - 4) = 0. 3. Apply Cayley-Hamilton: A^3 - 6A^2 + 9A - 4I = 0. 4. Rearrange to find A^-1: Multiply by A^-1 to get A^-1 = (1/4)*(6A - A^2 + 4I), but more directly, 4I = 6A - A^2 + A^3, so 4A^-1 = 6I - A + A^2. 5. Compute A^2: A^2 = [[7, 6, 9], [5, 6, 6], [5, 5, 7]]. 6. Calculate A^-1 = (1/4)*(6*I - A + A^2). Substituting the matrices: A^-1 = (1/4) * ([[6, 0, 0], [0, 6, 0], [0, 0, 6]] - [[2, 1, 2], [1, 2, 1], [1, 1, 2]] + [[7, 6, 9], [5, 6, 6], [5, 5, 7]]) = (1/4) * [[11, 5, 7], [4, 10, 5], [4, 4, 11]]. Resulting in A^-1 = [[2.75, 1.25, 1.75], [1, 2.5, 1.25], [1, 1, 2.75]].','A = \\begin{pmatrix} 2 & 1 & 2 \\\\ 1 & 2 & 1 \\\\ 1 & 1 & 2 \\end{pmatrix}. \\text{Characteristic equation: } \\det(A - \\lambda I) = -\\lambda^3 + 6\\lambda^2 - 9\\lambda + 4 = 0. \\text{By Cayley-Hamilton, } A^3 - 6A^2 + 9A - 4I = 0. \\text{Multiplying by } A^{-1}: A^2 - 6A + 9I - 4A^{-1} = 0 \\implies 4A^{-1} = A^2 - 6A + 9I. \\text{Compute } A^2 = \\begin{pmatrix} 7 & 6 & 9 \\\\ 5 & 6 & 6 \\\\ 5 & 5 & 7 \\end{pmatrix}. \\text{Then } 4A^{-1} = \\begin{pmatrix} 7 & 6 & 9 \\\\ 5 & 6 & 6 \\\\ 5 & 5 & 7 \\end{pmatrix} - \\begin{pmatrix} 12 & 6 & 12 \\\\ 6 & 12 & 6 \\\\ 6 & 6 & 12 \\end{pmatrix} + \\begin{pmatrix} 9 & 0 & 0 \\\\ 0 & 9 & 0 \\\\ 0 & 0 & 9 \\end{pmatrix} = \\begin{pmatrix} 4 & 0 & -3 \\\\ -1 & 3 & 0 \\\\ -1 & -1 & 4 \\end{pmatrix}. \\text{Adjusting for the inverse formula: } A^{-1} = \\frac{1}{4} \\begin{pmatrix} 3 & 0 & -3 \\\\ -1 & 2 & 0 \\\\ -1 & -1 & 3 \\end{pmatrix} \\text{ (Correction: Recalculating } 4A^{-1} = 6I - A + A^2 \\text{ yielded } \\frac{1}{4} \\begin{pmatrix} 11 & 5 & 7 \\\\ 4 & 10 & 5 \\\\ 4 & 4 & 11 \\end{pmatrix}).','A^{-1} = \\begin{pmatrix} 2.75 & 1.25 & 1.75 \\\\ 1 & 2.5 & 1.25 \\\\ 1 & 1 & 2.75 \\end{pmatrix}','[]','numerical','0.95',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('3cdd3841c6bcd259bf6e663998f9eab51b9e456cfbe53aee347f0e9fd65312bf','Mid Semester','Mathematics 1','MA24101','3','2022','Q.5(a)','Evaluate whether following limit exists or not. lim_((x,y)->(0,0)) xy^4 / (x² + y^8)','\\lim_{(x,y)\\to(0,0)} \\frac{xy^4}{x^2 + y^8}','To evaluate the limit of f(x, y) = xy^4 / (x^2 + y^8) as (x, y) approaches (0, 0), we test different paths of approach. First, consider the path along the x-axis (y = 0), which gives f(x, 0) = 0/x^2 = 0, so the limit along this path is 0. Next, consider paths of the form x = cy^k. Setting x = y^4, the expression becomes (y^4 * y^4) / ((y^4)^2 + y^8) = y^8 / (y^8 + y^8) = y^8 / (2y^8) = 1/2. Since the limit is 0 along one path and 1/2 along another path, the limit does not exist.','\\text{Consider } f(x,y) = \\frac{xy^4}{x^2 + y^8}. \\text{ Path 1: Along the x-axis } (y=0), \\lim_{x\\to 0} f(x,0) = \\lim_{x\\to 0} \\frac{0}{x^2} = 0. \\text{ Path 2: Let } x = y^4. \\text{ Substituting this into the function yields: } \\lim_{y\\to 0} \\frac{(y^4)y^4}{(y^4)^2 + y^8} = \\lim_{y\\to 0} \\frac{y^8}{y^8 + y^8} = \\lim_{y\\to 0} \\frac{y^8}{2y^8} = \\frac{1}{2}. \\text{ Since } 0 \\neq \\frac{1}{2}, \\text{ the limit does not exist.}','The limit does not exist.','[]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('33b28f8e1a5f8fb364f28a9e7586e493afe8abfa4c453e9bcba1379acab88b2d','Mid Semester','Mathematics 1','MA24101','3','2022','Q.5(b)','If u = x^y; check whether partial³ u / (partial x² partial y) = partial³ u / (partial x partial y partial x) or not.','u = x^y; \\text{ check } \\frac{\\partial^3 u}{\\partial x^2 \\partial y} = \\frac{\\partial^3 u}{\\partial x \\partial y \\partial x}','Conceptual Analysis: We are testing the equality of mixed partial derivatives of the function u(x, y) = x^y. According to Clairaut\'s Theorem (or Schwarz\'s Theorem), mixed partial derivatives are equal if the function and its partial derivatives are continuous in the domain. Since u(x, y) = e^(y ln x) is infinitely differentiable for x > 0, we expect equality. \n\nStep 1: Calculate the first partial derivatives. \n∂u/∂x = y*x^(y-1); ∂u/∂y = x^y * ln(x).\n\nStep 2: Calculate the second mixed partials. \nFor (∂²u/∂x∂y): ∂/∂x(x^y * ln(x)) = y*x^(y-1)*ln(x) + x^y*(1/x) = y*x^(y-1)*ln(x) + x^(y-1).\nFor (∂²u/∂y∂x): ∂/∂y(y*x^(y-1)) = x^(y-1) + y*x^(y-1)*ln(x).\n\nStep 3: Calculate the third partial derivatives. \nFor (∂³u/∂x²∂y): ∂/∂x(y*x^(y-1)*ln(x) + x^(y-1)) = y*(y-1)*x^(y-2)*ln(x) + y*x^(y-1)*(1/x) + (y-1)*x^(y-2) = y(y-1)x^(y-2)ln(x) + y*x^(y-2) + (y-1)x^(y-2) = y(y-1)x^(y-2)ln(x) + (2y-1)x^(y-2).\nFor (∂³u/∂x∂y∂x): ∂/∂x(x^(y-1) + y*x^(y-1)*ln(x)) = (y-1)x^(y-2) + y(y-1)x^(y-2)ln(x) + y*x^(y-2) = (2y-1)x^(y-2) + y(y-1)x^(y-2)ln(x).\n\nInterpretation: The two expressions are identical, confirming the equality.','u(x, y) = x^y = e^{y \\ln x}. \\\\ \\text{Step 1: } \\frac{\\partial u}{\\partial x} = y x^{y-1}, \\frac{\\partial u}{\\partial y} = x^y \\ln x. \\\\ \\text{Step 2: } \\frac{\\partial^2 u}{\\partial x \\partial y} = \\frac{\\partial}{\\partial x}(x^y \\ln x) = y x^{y-1} \\ln x + x^y \\cdot \\frac{1}{x} = y x^{y-1} \\ln x + x^{y-1}. \\\\ \\frac{\\partial^2 u}{\\partial y \\partial x} = \\frac{\\partial}{\\partial y}(y x^{y-1}) = x^{y-1} + y x^{y-1} \\ln x. \\\\ \\text{Step 3: } \\frac{\\partial^3 u}{\\partial x^2 \\partial y} = \\frac{\\partial}{\\partial x}(y x^{y-1} \\ln x + x^{y-1}) = y(y-1)x^{y-2} \\ln x + y x^{y-2} + (y-1)x^{y-2} = y(y-1)x^{y-2} \\ln x + (2y-1)x^{y-2}. \\\\ \\frac{\\partial^3 u}{\\partial x \\partial y \\partial x} = \\frac{\\partial}{\\partial x}(x^{y-1} + y x^{y-1} \\ln x) = (y-1)x^{y-2} + y(y-1)x^{y-2} \\ln x + y x^{y-2} = y(y-1)x^{y-2} \\ln x + (2y-1)x^{y-2}. \\\\ \\therefore \\frac{\\partial^3 u}{\\partial x^2 \\partial y} = \\frac{\\partial^3 u}{\\partial x \\partial y \\partial x}','\\frac{\\partial^3 u}{\\partial x^2 \\partial y} = \\frac{\\partial^3 u}{\\partial x \\partial y \\partial x}','[]','analytical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('23a1f10b1b46b3d7c8e2088a4700e9502bfc30fe916c09d3925d3039b18582d7','Mid Semester','Mathematics 1','MA24101','1','2023','Q.1(a)','Discuss the convergence of the sequence < n / (n²+1) >.','\\left< \\frac{n}{n^2+1} \\right>','To determine the convergence of the sequence a_n = n / (n^2 + 1), we examine the limit as n approaches infinity. Conceptually, for large n, the term n^2 dominates the denominator, making the sequence behave like n / n^2 = 1/n. Since 1/n approaches 0 as n increases, we expect the sequence to converge to 0. We verify this by dividing the numerator and denominator by n^2 to evaluate the limit rigorously.','\\text{Consider the limit of the sequence as } n \\to \\infty: \\lim_{n \\to \\infty} \\frac{n}{n^2+1} = \\lim_{n \\to \\infty} \\frac{n/n^2}{(n^2+1)/n^2} = \\lim_{n \\to \\infty} \\frac{1/n}{1 + 1/n^2}. \\text{Applying limit laws:} \\frac{\\lim_{n \\to \\infty} (1/n)}{\\lim_{n \\to \\infty} (1 + 1/n^2)} = \\frac{0}{1+0} = 0. \\text{Thus, the sequence converges to 0.}','0','[]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('3daa88f528af08af818b580bd99488a1cf7eaa8db20e3f3758772bfa00e4239f','Mid Semester','Mathematics 1','MA24101','1','2023','Q.1(b)','Test the convergence of the series: sum_(n=1)^infinity n / sqrt(2(n+1))','\\sum_{n=1}^{\\infty} \\frac{n}{\\sqrt{2(n+1)}}','1. Conceptual Analysis: The general term of the series is a_n = n / sqrt(2(n+1)). As n approaches infinity, the numerator behaves like n and the denominator behaves like sqrt(2n) = sqrt(2) * n^(1/2). Thus, the general term behaves like (1/sqrt(2)) * n^(1/2). Since the power of n in the numerator is greater than in the denominator (specifically, 1 > 1/2), the general term does not approach zero. 2. Working: According to the n-th term test for divergence, a series sum(a_n) can only converge if lim(n->inf) a_n = 0. Here, lim(n->inf) n / sqrt(2(n+1)) = lim(n->inf) n / (sqrt(2) * sqrt(n+1)). Dividing numerator and denominator by sqrt(n), we get lim(n->inf) sqrt(n) / (sqrt(2) * sqrt(1 + 1/n)) = inf. 3. Interpretation: Since the limit of the general term is infinity, which is not zero, the series diverges by the Test for Divergence.','The \\text{n-th term test for divergence states that if } \\lim_{n \\to \\infty} a_n \\neq 0, \\text{ then the series } \\sum a_n \\text{ diverges.} \\\\ \\text{Let } a_n = \\frac{n}{\\sqrt{2(n+1)}}. \\\\ \\text{We evaluate the limit of the general term as } n \\to \\infty: \\\\ \\lim_{n \\to \\infty} \\frac{n}{\\sqrt{2}\\sqrt{n+1}} = \\lim_{n \\to \\infty} \\frac{1}{\\sqrt{2}} \\cdot \\frac{n}{\\sqrt{n+1}}. \\\\ \\text{Since } \\frac{n}{\\sqrt{n+1}} \\approx \\frac{n}{\\sqrt{n}} = \\sqrt{n} \\to \\infty \\text{ as } n \\to \\infty, \\\\ \\lim_{n \\to \\infty} a_n = \\infty. \\\\ \\text{Because the limit is not zero, the series diverges.}','Diverges','[]','analytical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('a71ca684bfd50ed2b45a40b20ca987fdee0ea4a634cf9b7c8935a1971d1388f9','Mid Semester','Mathematics 1','MA24101','1','2023','Q.2(a)','Using the Cauchy’s integral test, examine the convergence of the series: sum_(n=1)^infinity n e^(-n²).','\\sum_{n=1}^{\\infty} n e^{-n^2}','1. Conceptual Analysis: The series sum_{n=1}^infinity n * e^(-n^2) consists of positive terms where the general term a_n = n * e^(-n^2) decreases as n increases. Since f(x) = x * e^(-x^2) is continuous, positive, and monotonically decreasing for x >= 1, we can apply Cauchy\'s Integral Test by comparing the sum to the improper integral int_1^infinity x * e^(-x^2) dx. 2. Integration: We evaluate I = limit_{t to infinity} int_1^t x * e^(-x^2) dx. Using u-substitution where u = -x^2, du = -2x dx, the integral becomes -1/2 * int e^u du = -1/2 * e^(-x^2). Evaluating from 1 to t gives -1/2 * (e^(-t^2) - e^(-1)). 3. Limit: As t approaches infinity, e^(-t^2) approaches 0. The limit is 1/(2e), which is a finite value. 4. Interpretation: Since the improper integral converges to 1/(2e), the original series must also converge by the Cauchy Integral Test.','\\text{Let } f(x) = x e^{-x^2}. \\text{ Since } f\'(x) = e^{-x^2}(1 - 2x^2) < 0 \\text{ for } x > 1/\\sqrt{2}, f(x) \\text{ is continuous, positive, and decreasing on } [1, \\infty). \\text{ The integral test states that } \\sum_{n=1}^{\\infty} f(n) \\text{ converges if } \\int_{1}^{\\infty} x e^{-x^2} dx \\text{ converges.} \\newline \\int_{1}^{\\infty} x e^{-x^2} dx = \\lim_{t \\to \\infty} \\int_{1}^{t} x e^{-x^2} dx. \\newline \\text{Let } u = -x^2, du = -2x dx \\implies x dx = -\\frac{1}{2} du. \\newline \\int x e^{-x^2} dx = -\\frac{1}{2} e^{-x^2}. \\newline \\lim_{t \\to \\infty} \\left[ -\\frac{1}{2} e^{-x^2} \\right]_1^t = \\lim_{t \\to \\infty} \\left( -\\frac{1}{2}e^{-t^2} + \\frac{1}{2}e^{-1} \\right) = \\frac{1}{2e}. \\text{ Since the integral converges, the series converges.}','The series converges.','[]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('be7ff5657f8b63578e4655ef5b4c6cb34fcc5f19dfcf33b1caa2d4a699bb61df','Mid Semester','Mathematics 1','MA24101','1','2023','Q.2(b)','Apply the Leibnitz’s test, check the convergence of the series: sum_(n=1)^infinity (-1)^(n-1) / (3n-2)','\\sum_{n=1}^{\\infty} \\frac{(-1)^{n-1}}{3n-2}','To determine the convergence of the alternating series sum_{n=1}^infinity (-1)^(n-1) / (3n-2), we apply the Leibniz Test (Alternating Series Test). The test requires two conditions for a series of the form sum (-1)^(n-1) b_n to converge: 1) The sequence b_n must be monotonically decreasing (b_{n+1} <= b_n), and 2) the limit of b_n as n approaches infinity must be 0. Here, b_n = 1/(3n-2). First, we observe that as n increases, the denominator (3n-2) increases, hence b_n decreases for all n >= 1. Second, we calculate the limit: lim_{n->infinity} 1/(3n-2) = 0. Since both conditions are satisfied, the series converges.','\\text{Let } b_n = \\frac{1}{3n-2}. \\text{ The series is } \\sum_{n=1}^{\\infty} (-1)^{n-1} b_n. \\text{ Leibniz\'s Test criteria: } \\newline 1) \\text{ Monotonicity: } b_{n+1} = \\frac{1}{3(n+1)-2} = \\frac{1}{3n+1}. \\text{ Since } 3n+1 > 3n-2 \\text{ for all } n \\ge 1, \\text{ it follows that } \\frac{1}{3n+1} < \\frac{1}{3n-2}, \\text{ so } b_{n+1} < b_n. \\newline 2) \\text{ Limit: } \\lim_{n \\to \\infty} b_n = \\lim_{n \\to \\infty} \\frac{1}{3n-2} = 0. \\newline \\text{Since both conditions are met, the series converges by the Alternating Series Test.}','The series converges.','[]','analytical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('8aa9606c2dd8f892913244e9356b7353ded0b566f7cffb3191968ffa23cd60c7','Mid Semester','Mathematics 1','MA24101','2','2023','Q.3(a)','Find the rank of the matrix: [[1, 2, 3], [1, 4, 2], [2, 6, 5]]','\\begin{pmatrix} 1 & 2 & 3 \\\\ 1 & 4 & 2 \\\\ 2 & 6 & 5 \\end{pmatrix}','1. Identify the given matrix A = [[1, 2, 3], [1, 4, 2], [2, 6, 5]]. The goal is to find its rank. 2. Use Gaussian elimination to transform the matrix into row-echelon form. The rank is the number of non-zero rows. 3. Subtract row 1 from row 2 (R2 - R1 -> R2): [[1, 2, 3], [0, 2, -1], [2, 6, 5]]. Subtract 2 times row 1 from row 3 (R3 - 2R1 -> R3): [[1, 2, 3], [0, 2, -1], [0, 2, -1]]. 4. Subtract row 2 from row 3 (R3 - R2 -> R3): [[1, 2, 3], [0, 2, -1], [0, 0, 0]]. 5. There are 2 non-zero rows, therefore the rank is 2.','A = \\begin{pmatrix} 1 & 2 & 3 \\\\ 1 & 4 & 2 \\\\ 2 & 6 & 5 \\end{pmatrix} \\xrightarrow{R_2 \\gets R_2 - R_1, R_3 \\gets R_3 - 2R_1} \\begin{pmatrix} 1 & 2 & 3 \\\\ 0 & 2 & -1 \\\\ 0 & 2 & -1 \\end{pmatrix} \\xrightarrow{R_3 \\gets R_3 - R_2} \\begin{pmatrix} 1 & 2 & 3 \\\\ 0 & 2 & -1 \\\\ 0 & 0 & 0 \\end{pmatrix}. \\text{Since there are two non-zero rows in the row-echelon form, the rank is 2.}','2','[]','numerical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('dc9beaa55d131b846ad5961e54e52d6a3d9184fc7619df964452aa82ac150f84','Mid Semester','Mathematics 1','MA24101','2','2023','Q.3(b)','Test the consistency of the system of equations: 2x - 3y + 7z = 5; 3x + y - 3z = 13; 2x + 19y - 47z = 32.','2x - 3y + 7z = 5; 3x + y - 3z = 13; 2x + 19y - 47z = 32.','To test the consistency of the system, we represent it as an augmented matrix [A|B] and perform Gaussian elimination to reach row-echelon form. The system is consistent if the rank of the coefficient matrix A is equal to the rank of the augmented matrix [A|B]. Step 1: Write the augmented matrix. Step 2: Use row operations to create zeros below the main diagonal. Step 3: Analyze the final row to see if a contradiction occurs (e.g., 0 = non-zero value).','\\begin{pmatrix} 2 & -3 & 7 & | & 5 \\\\ 3 & 1 & -3 & | & 13 \\\\ 2 & 19 & -47 & | & 32 \\end{pmatrix} \\xrightarrow{R_3 - R_1 \\to R_3} \\begin{pmatrix} 2 & -3 & 7 & | & 5 \\\\ 3 & 1 & -3 & | & 13 \\\\ 0 & 22 & -54 & | & 27 \\end{pmatrix} \\xrightarrow{2R_2 - 3R_1 \\to R_2} \\begin{pmatrix} 2 & -3 & 7 & | & 5 \\\\ 0 & 11 & -27 & | & 11 \\\\ 0 & 22 & -54 & | & 27 \\end{pmatrix} \\xrightarrow{R_3 - 2R_2 \\to R_3} \\begin{pmatrix} 2 & -3 & 7 & | & 5 \\\\ 0 & 11 & -27 & | & 11 \\\\ 0 & 0 & 0 & | & 5 \\end{pmatrix}. \\text{ The last row implies } 0x + 0y + 0z = 5, \\text{ which is a contradiction } (0=5).','Inconsistent','[]','analytical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('16b04511b15261fba9dfd4f93f62edd0ff6d2aecd4a08838b0df335d9766c76b','Mid Semester','Mathematics 1','MA24101','2','2023','Q.4','Find the eigenvalues and eigenvectors of the matrix: [[3, 1, 4], [0, 2, 0], [0, 0, 5]]','\\begin{pmatrix} 3 & 1 & 4 \\\\ 0 & 2 & 0 \\\\ 0 & 0 & 5 \\end{pmatrix}','1. Identify the matrix A = [[3, 1, 4], [0, 2, 0], [0, 0, 5]]. The goal is to find eigenvalues λ such that det(A - λI) = 0 and corresponding eigenvectors v such that (A - λI)v = 0.\n2. Since the matrix is upper triangular, the eigenvalues are simply the diagonal entries: λ1 = 3, λ2 = 2, λ3 = 5.\n3. For λ1 = 3: (A - 3I)v = 0 leads to [[0, 1, 4], [0, -1, 0], [0, 0, 2]]v = 0. Solving this yields v1 = [1, 0, 0]ᵀ.\n4. For λ2 = 2: (A - 2I)v = 0 leads to [[1, 1, 4], [0, 0, 0], [0, 0, 3]]v = 0. Solving this yields v2 = [1, -1, 0]ᵀ.\n5. For λ3 = 5: (A - 5I)v = 0 leads to [[-2, 1, 4], [0, -3, 0], [0, 0, 0]]v = 0. From -3y = 0, y = 0. Then -2x + 4z = 0, so x = 2z. Setting z = 1, v3 = [2, 0, 1]ᵀ.','Given A = \\begin{pmatrix} 3 & 1 & 4 \\\\ 0 & 2 & 0 \\\\ 0 & 0 & 5 \\end{pmatrix}. The characteristic equation is \\det(A - \\lambda I) = (3 - \\lambda)(2 - \\lambda)(5 - \\lambda) = 0. The eigenvalues are \\lambda_1 = 3, \\lambda_2 = 2, \\lambda_3 = 5. For \\lambda_1 = 3: \\begin{pmatrix} 0 & 1 & 4 \\\\ 0 & -1 & 0 \\\\ 0 & 0 & 2 \\end{pmatrix} \\begin{pmatrix} x \\\\ y \\\\ z \\end{pmatrix} = 0 \\implies y=0, z=0, x=t \\implies v_1 = \\begin{pmatrix} 1 \\\\ 0 \\\\ 0 \\end{pmatrix}. For \\lambda_2 = 2: \\begin{pmatrix} 1 & 1 & 4 \\\\ 0 & 0 & 0 \\\\ 0 & 0 & 3 \\end{pmatrix} \\begin{pmatrix} x \\\\ y \\\\ z \\end{pmatrix} = 0 \\implies z=0, x+y=0 \\implies v_2 = \\begin{pmatrix} 1 \\\\ -1 \\\\ 0 \\end{pmatrix}. For \\lambda_3 = 5: \\begin{pmatrix} -2 & 1 & 4 \\\\ 0 & -3 & 0 \\\\ 0 & 0 & 0 \\end{pmatrix} \\begin{pmatrix} x \\\\ y \\\\ z \\end{pmatrix} = 0 \\implies y=0, -2x+4z=0 \\implies v_3 = \\begin{pmatrix} 2 \\\\ 0 \\\\ 1 \\end{pmatrix}.','λ1=3, v1=[1, 0, 0]ᵀ; λ2=2, v2=[1, -1, 0]ᵀ; λ3=5, v3=[2, 0, 1]ᵀ','[]','numerical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('32e9add756887f8b6c2d4e89218422f8c5cac123e9f64778bf680969eac31455','Mid Semester','Mathematics 1','MA24101','3','2023','Q.5(a)','Show that limit of the function: lim_((x,y)->(0,0)) (x²-y²)/(x²+y²) does not exist.','\\lim_{(x,y)\\to(0,0)} \\frac{x^2-y^2}{x^2+y^2}','To determine if the limit exists, we examine the behavior of the function f(x, y) = (x^2 - y^2) / (x^2 + y^2) as (x, y) approaches (0, 0) along different paths. If the limit exists, it must be the same regardless of the path taken. First, approach along the x-axis (where y = 0). The function becomes f(x, 0) = x^2 / x^2 = 1, so the limit is 1. Next, approach along the y-axis (where x = 0). The function becomes f(0, y) = -y^2 / y^2 = -1, so the limit is -1. Since the function approaches two different values along these two paths, the limit does not exist.','\\text{Let } f(x,y) = \\frac{x^2-y^2}{x^2+y^2}. \\text{ To show the limit does not exist, consider two paths approaching } (0,0): \\newline 1) \\text{ Along the x-axis, set } y=0: \\lim_{x\\to 0} f(x,0) = \\lim_{x\\to 0} \\frac{x^2-0}{x^2+0} = \\lim_{x\\to 0} (1) = 1. \\newline 2) \\text{ Along the y-axis, set } x=0: \\lim_{y\\to 0} f(0,y) = \\lim_{y\\to 0} \\frac{0-y^2}{0+y^2} = \\lim_{y\\to 0} (-1) = -1. \\newline \\text{Since } 1 \\neq -1, \\text{ the limit depends on the path taken. Therefore, } \\lim_{(x,y)\\to(0,0)} \\frac{x^2-y^2}{x^2+y^2} \\text{ does not exist.}','Does not exist','["Programming Concepts"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('e98bfd60f6a143ca46afe29eb91fb370dc45b92c0f2e3389b79af1dcc8719af0','Mid Semester','Mathematics 1','MA24101','3','2023','Q.5(b)','Find the partial derivatives f_x(0,0) and f_y(0,0) of the function: f(x, y) = (x³-y³)/(x²+y²), (x, y) != (0,0).','f(x, y) = \\frac{x^3-y^3}{x^2+y^2}','To find the partial derivatives at (0,0), we use the limit definition since the function is defined piecewise. For f_x(0,0), the derivative is defined as the limit as h approaches 0 of (f(h,0) - f(0,0))/h. We assume f(0,0) = 0 for continuity if defined, or explicitly use the limit definition: f_x(0,0) = lim_{h->0} [((h^3-0^3)/(h^2+0^2)) - f(0,0)]/h. Evaluating this gives lim_{h->0} (h^3/h^2)/h = lim_{h->0} h/h = 1. For f_y(0,0), the definition is the limit as k approaches 0 of (f(0,k) - f(0,0))/k. This gives lim_{k->0} [((0^3-k^3)/(0^2+k^2)) - 0]/k = lim_{k->0} (-k^3/k^2)/k = lim_{k->0} -k/k = -1.','f_x(0,0) = \\lim_{h \\to 0} \\frac{f(h,0) - f(0,0)}{h} = \\lim_{h \\to 0} \\frac{\\frac{h^3-0}{h^2+0} - 0}{h} = \\lim_{h \\to 0} \\frac{h}{h} = 1. \\\\ f_y(0,0) = \\lim_{k \\to 0} \\frac{f(0,k) - f(0,0)}{k} = \\lim_{k \\to 0} \\frac{\\frac{0-k^3}{0+k^2} - 0}{k} = \\lim_{k \\to 0} \\frac{-k}{k} = -1.','f_x(0,0) = 1, f_y(0,0) = -1','["Programming Concepts"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);